538→export function createAnthropicProxyHandler(
539→  deps: ServerDependencies,
540→): (request: Request) => Promise<Response> {
541→  const workspaceCache: WorkspaceCache = new Map();
542→  const rateLimiterState: RateLimiterState = createRateLimiterState();
543→  const spendCache: SpendCache = new Map();
544→  const noPolicyWarnedWorkspaces = new Set<string>();
545→  const contextCache: ContextCache = createContextCache(300); // default TTL, overridden per-workspace
546→
547→  // Periodic pruning of stale rate limiter entries to prevent unbounded Map growth.
548→  // unref() ensures this interval does not keep the process alive on shutdown.
549→  const pruneInterval = setInterval(
550→    () => pruneStaleEntries(rateLimiterState, Date.now()),
551→    5 * 60 * 1000,
552→  );
553→  pruneInterval.unref();
554→
555→  const anthropicApiUrl = deps.config.anthropicApiUrl;
556→
557→  return async (request: Request): Promise<Response> => {
558→    const startedAt = performance.now();
559→    const url = new URL(request.url);
560→    const upstreamPath = url.pathname.replace(/^\/proxy\/llm\/anthropic/, "");
561→    const upstreamUrl = `${anthropicApiUrl}${upstreamPath}`;
562→    const isCountTokens = isCountTokensRequest(url.pathname);
563→
564→    // --- Step 1: Parse request body (malformed body forwarded as-is) ---
565→    const body = await request.text();
566→    const parsed = tryParseRequestBody(body);
567→    const isStreaming = parsed?.stream === true;
568→
569→    // --- Step 2: Identity resolution ---
570→    const identitySignals = resolveIdentity({
571→      metadataUserId: parsed?.metadata?.user_id,
572→      workspaceHeader: request.headers.get("X-Brain-Workspace") ?? undefined,
573→      taskHeader: request.headers.get("X-Brain-Task") ?? undefined,
574→      agentTypeHeader: request.headers.get("X-Brain-Agent-Type") ?? undefined,
575→      sessionHeader: request.headers.get("X-Brain-Session") ?? undefined,
576→    });
577→
578→    // --- Step 3: Session ID resolution ---
579→    const effectiveSessionId = resolveSessionId(identitySignals);
580→
581→    // --- Step 3.5: Conversation hash resolution (pure) ---
582→    const conversationHashInput: ConversationHashInput = {
583→      systemPrompt: typeof parsed?.system === "string" ? parsed.system : undefined,
584→      systemPromptBlocks: Array.isArray(parsed?.system) ? parsed.system : undefined,
585→      messages: parsed?.messages ?? [],
586→    };
587→    const conversationHash = resolveConversationHash(conversationHashInput);
588→
589→    // --- Conversation upsert (async, non-blocking) ---
590→    let conversationId: string | undefined;
591→    if (conversationHash && identitySignals.workspaceId) {
592→      try {
593→        const conversationRecord = await upsertConversation(
594→          {
595→            conversationId: conversationHash.conversationId,
596→            workspaceId: identitySignals.workspaceId,
597→            title: conversationHash.title,
598→          },
599→          { surreal: deps.surreal },
600→        );
601→        if (conversationRecord) {
602→          conversationId = conversationHash.conversationId;
603→        }
604→      } catch (error) {
605→        logWarn("proxy.anthropic.conversation_upsert_failed", "Conversation upsert failed — continuing without conversation link", {
606→          error: String(error),
607→        });
608→      }
609→    }
610→
611→    // --- Workspace validation (non-blocking) ---
612→    if (identitySignals.workspaceId) {
613→      const isValid = await validateWorkspace(
614→        deps.surreal,
615→        identitySignals.workspaceId,
616→        workspaceCache,
617→      );
618→      if (!isValid) {
619→        logWarn("proxy.anthropic.invalid_workspace", "Workspace not found in database", {
620→          workspaceId: identitySignals.workspaceId,
621→        });
622→      }
623→    }
624→
625→    // --- Step 4: Policy evaluation ---
626→    let policyResult: ProxyPolicyResult | undefined;
627→    if (parsed?.model && !isCountTokens) {
628→      const policyDeps: ProxyPolicyDependencies = {
629→        surreal: deps.surreal,
630→        inflight: deps.inflight,
631→        rateLimiterState,
632→        spendCache,
633→      };
634→
635→      policyResult = await evaluateProxyPolicy(
636→        {
637→          workspaceId: identitySignals.workspaceId ?? "",
638→          agentType: identitySignals.agentType,
639→          model: parsed.model,
640→        },
641→        policyDeps,
642→        noPolicyWarnedWorkspaces,
643→      );
644→
645→      if (policyResult.decision !== "allow") {
646→        return buildPolicyDenialResponse(policyResult);
647→      }
648→    }
649→
650→    // --- Step 5: Context injection (fail-open) ---
651→    let effectiveBody = body;
652→    let injectionResult: InjectionResult | undefined;
653→
654→    if (parsed && identitySignals.workspaceId && !isCountTokens) {
655→      try {
656→        const intelligenceConfig = await loadIntelligenceConfig(deps.surreal, identitySignals.workspaceId);
657→        const contextResult = await runContextInjection(
658→          deps,
659→          identitySignals.workspaceId,
660→          parsed,
661→          body,
662→          contextCache,
663→          intelligenceConfig,
664→        );
665→        effectiveBody = contextResult.body;
666→        injectionResult = contextResult.injectionResult;
667→      } catch (error) {
668→        // Fail-open: log warning and continue with original body
669→        logWarn("proxy.context_injection.failed", "Context injection failed, forwarding original request", {
670→          workspace_id: identitySignals.workspaceId,
671→          error: String(error),
672→        });
673→      }
674→    }
675→
676→    // --- API key validation ---
677→    const hasApiKey = request.headers.has("x-api-key");
678→    const hasAuthHeader = request.headers.has("authorization");
679→    if (!hasApiKey && !hasAuthHeader) {
