  1→/**
  2→ * Trace Writer — Async trace capture for LLM proxy calls
  3→ *
  4→ * Creates llm_call trace nodes in SurrealDB after stream/response completion.
  5→ * All graph writes are async via deps.inflight.track() to avoid blocking
  6→ * response delivery.
  7→ *
  8→ * Port: (TraceData, Dependencies) -> Promise<void>
  9→ * Side effects: SurrealDB writes (boundary adapter)
 10→ */
 11→
 12→import { RecordId } from "surrealdb";
 13→import { logInfo, logError, logWarn } from "../http/observability";
 14→import { calculateCost, type TokenUsage } from "./cost-calculator";
 15→import { getModelPricing } from "./pricing-table";
 16→import type { Surreal } from "surrealdb";
 17→
 18→// ---------------------------------------------------------------------------
 19→// Types
 20→// ---------------------------------------------------------------------------
 21→
 22→export type TraceData = {
 23→  readonly model: string;
 24→  readonly inputTokens: number;
 25→  readonly outputTokens: number;
 26→  readonly cacheCreationTokens: number;
 27→  readonly cacheReadTokens: number;
 28→  readonly stopReason?: string;
 29→  readonly latencyMs: number;
 30→  readonly workspaceId?: string;
 31→  readonly sessionId?: string;
 32→  readonly taskId?: string;
 33→  readonly requestId?: string;
 34→  readonly conversationId?: string;
 35→  readonly policyDecision?: {
 36→    readonly decision: "pass" | "deny";
 37→    readonly policy_refs: string[];
 38→    readonly reason?: string;
 39→    readonly timestamp: string;
 40→  };
 41→  // Intelligence metadata (context injection)
 42→  readonly intelligenceMetadata?: {
 43→    readonly brain_context_injected: boolean;
 44→    readonly brain_context_decisions: number;
 45→    readonly brain_context_learnings: number;
 46→    readonly brain_context_observations: number;
 47→    readonly brain_context_tokens_est: number;
 48→  };
 49→  // Response content (opaque capture per ADR-051)
 50→  readonly responseContent?: {
 51→    readonly content_blocks: Array<{ type: string; text?: string; id?: string; name?: string; input?: unknown }>;
 52→    readonly stop_reason: string;
 53→    readonly usage: {
 54→      readonly input_tokens: number;
 55→      readonly output_tokens: number;
 56→      readonly cache_creation_tokens?: number;
 57→      readonly cache_read_tokens?: number;
 58→    };
 59→  };
 60→};
 61→
 62→type TraceDependencies = {
 63→  readonly surreal: Surreal;
 64→};
 65→
 66→// ---------------------------------------------------------------------------
 67→// Retry with Exponential Backoff
 68→// ---------------------------------------------------------------------------
 69→
 70→const MAX_RETRIES = 3;
 71→const BASE_DELAY_MS = 200;
 72→
 73→async function withRetry<T>(
 74→  operation: () => Promise<T>,
 75→  label: string,
 76→): Promise<T> {
 77→  let lastError: unknown;
 78→
 79→  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
 80→    try {
 81→      return await operation();
 82→    } catch (error) {
 83→      lastError = error;
 84→      if (attempt < MAX_RETRIES - 1) {
 85→        const delayMs = BASE_DELAY_MS * Math.pow(2, attempt);
 86→        logWarn("proxy.trace.retry", `Retry ${attempt + 1}/${MAX_RETRIES} for ${label}`, {
 87→          attempt: attempt + 1,
 88→          delay_ms: delayMs,
 89→        });
 90→        await new Promise(resolve => setTimeout(resolve, delayMs));
 91→      }
 92→    }
 93→  }
 94→
 95→  throw lastError;
 96→}
 97→
 98→// ---------------------------------------------------------------------------
 99→// Trace Node Creation
100→// ---------------------------------------------------------------------------
101→
102→async function createTraceNode(
103→  surreal: Surreal,
104→  traceId: string,
105→  data: TraceData,
106→  costUsd: number,
107→): Promise<RecordId> {
108→  const traceRecord = new RecordId("trace", traceId);
109→
110→  const content: Record<string, unknown> = {
111→    type: "llm_call",
112→    model: data.model,
113→    provider: "anthropic",
114→    input_tokens: data.inputTokens,
115→    output_tokens: data.outputTokens,
116→    cache_creation_tokens: data.cacheCreationTokens,
117→    cache_read_tokens: data.cacheReadTokens,
118→    cost_usd: costUsd,
119→    latency_ms: Math.round(data.latencyMs),
120→    stop_reason: data.stopReason ?? "end_turn",
121→    created_at: new Date(),
122→  };
123→
124→  // Set workspace directly on the trace node when known
125→  if (data.workspaceId) {
126→    content.workspace = new RecordId("workspace", data.workspaceId);
127→  }
128→
129→  if (data.requestId) {
130→    content.request_id = data.requestId;
131→  }
132→
133→  // Store conversation reference and intelligence metadata in FLEXIBLE input field
134→  {
135→    const inputData: Record<string, unknown> = {};
136→
137→    if (data.conversationId) {
138→      inputData.conversation = new RecordId("conversation", data.conversationId);
139→    }
140→
141→    if (data.intelligenceMetadata) {
142→      inputData.brain_context_injected = data.intelligenceMetadata.brain_context_injected;
143→      inputData.brain_context_decisions = data.intelligenceMetadata.brain_context_decisions;
144→      inputData.brain_context_learnings = data.intelligenceMetadata.brain_context_learnings;
145→      inputData.brain_context_observations = data.intelligenceMetadata.brain_context_observations;
146→      inputData.brain_context_tokens_est = data.intelligenceMetadata.brain_context_tokens_est;
147→    }
148→
149→    if (Object.keys(inputData).length > 0) {
150→      content.input = inputData;
151→    }
152→  }
153→
154→  // Store response content in FLEXIBLE output field (opaque capture per ADR-051)
155→  if (data.responseContent) {
156→    content.output = data.responseContent;
157→  }
158→
159→  if (data.policyDecision) {
160→    content.policy_decision = data.policyDecision;
161→  }
162→
163→  await surreal.query(`CREATE $trace CONTENT $content;`, {
164→    trace: traceRecord,
165→    content,
166→  });
167→
168→  return traceRecord;
169→}
170→
171→// ---------------------------------------------------------------------------
172→// Edge Creation
173→// ---------------------------------------------------------------------------
174→
175→async function createTraceEdges(
176→  surreal: Surreal,
177→  traceRecord: RecordId,
178→  data: TraceData,
179→): Promise<void> {
180→  // Always create workspace scope edge when workspace is known
181→  if (data.workspaceId) {
182→    const workspaceRecord = new RecordId("workspace", data.workspaceId);
183→    await surreal.query(
184→      `RELATE $trace->scoped_to->$workspace SET created_at = time::now();`,
185→      { trace: traceRecord, workspace: workspaceRecord },
186→    );
187→  }
188→
189→  // Create session invocation edge when session is resolved
190→  if (data.sessionId) {
191→    const sessionRecord = new RecordId("agent_session", data.sessionId);
192→    await surreal.query(
193→      `RELATE $session->invoked->$trace SET created_at = time::now();`,
194→      { session: sessionRecord, trace: traceRecord },
195→    );
196→  }
197→
198→  // Create task attribution edge when task is resolved
199→  if (data.taskId) {
200→    const taskRecord = new RecordId("task", data.taskId);
201→    await surreal.query(
202→      `RELATE $trace->attributed_to->$task SET created_at = time::now();`,
203→      { trace: traceRecord, task: taskRecord },
204→    );
205→  }
206→
207→  // Create governed_by edges for policy audit trail
208→  if (data.policyDecision) {
209→    for (const policyId of data.policyDecision.policy_refs) {
210→      const policyRecord = new RecordId("policy", policyId);
211→      await surreal.query(
212→        `RELATE $trace->governed_by->$policy SET created_at = time::now(), decision = $decision;`,
213→        {
214→          trace: traceRecord,
215→          policy: policyRecord,
216→          decision: data.policyDecision.decision,
217→        },
218→      );
219→    }
220→  }
221→}
222→
223→// ---------------------------------------------------------------------------
224→// Public API
225→// ---------------------------------------------------------------------------
226→
227→/**
228→ * Capture an LLM call trace asynchronously.
229→ *
230→ * Computes cost from the pricing table, creates a trace node, and
231→ * establishes relationship edges. All operations are retried 3x with
232→ * exponential backoff. On persistent failure, logs structured output
233→ * instead of throwing.
234→ *
235→ * This function returns a Promise that should be tracked via
236→ * deps.inflight.track() — it must NOT block response delivery.
237→ */
238→export async function captureTrace(
239→  data: TraceData,
240→  deps: TraceDependencies,
241→): Promise<void> {
242→  const traceId = crypto.randomUUID();
243→
244→  // Compute cost from pricing table (pure)
245→  const usage: TokenUsage = {
246→    inputTokens: data.inputTokens,
247→    outputTokens: data.outputTokens,
248→    cacheCreationTokens: data.cacheCreationTokens,
249→    cacheReadTokens: data.cacheReadTokens,
250→  };
251→  const pricing = getModelPricing(data.model);
252→  const costUsd = calculateCost(usage, pricing);
253→
254→  try {
255→    // Create trace node with retry
256→    const traceRecord = await withRetry(
257→      () => createTraceNode(deps.surreal, traceId, data, costUsd),
258→      "trace_node_create",
259→    );
260→
261→    // Create edges with retry
262→    await withRetry(
263→      () => createTraceEdges(deps.surreal, traceRecord, data),
264→      "trace_edges_create",
265→    );
266→
267→    logInfo("proxy.trace.captured", "LLM call trace captured", {
268→      trace_id: traceId,
269→      model: data.model,
270→      cost_usd: costUsd,
271→      workspace_id: data.workspaceId,
272→    });
273→  } catch (error) {
274→    // Fallback: structured log output when graph write fails after retries
275→    logError("proxy.trace.write_failed", "Failed to write trace after retries, logging fallback", error);
276→    logInfo("proxy.trace.fallback", "Trace data (graph write failed)", {
277→      trace_id: traceId,
278→      model: data.model,
279→      input_tokens: data.inputTokens,
280→      output_tokens: data.outputTokens,
281→      cache_creation_tokens: data.cacheCreationTokens,
282→      cache_read_tokens: data.cacheReadTokens,
283→      cost_usd: costUsd,
284→      latency_ms: Math.round(data.latencyMs),
285→      stop_reason: data.stopReason,
286→      workspace_id: data.workspaceId,
287→      session_id: data.sessionId,
288→      task_id: data.taskId,
289→    });
290→  }
291→}
