  1→/**
  2→ * Anthropic LLM Proxy Route
  3→ *
  4→ * Transparent proxy that forwards requests to Anthropic's Messages API
  5→ * with identity resolution, session tracking, and workspace validation.
  6→ *
  7→ * Pipeline execution order:
  8→ * 1. Identity resolution (from metadata + headers)
  9→ * 2. Session ID resolution (header priority over metadata)
 10→ * 3. Conversation hash (03-01) — deterministic UUIDv5 from content
 11→ * 4. Policy evaluation [future 02-01]
 12→ * 5. Context injection [future 03-02]
 13→ * 6. Request forwarding
 14→ * 7. Async trace capture (01-03) + conversation upsert
 15→ */
 16→import { logInfo, logError, logWarn, elapsedMs } from "../http/observability";
 17→import { jsonResponse } from "../http/response";
 18→import { resolveIdentity } from "./identity-resolver";
 19→import { resolveSessionId } from "./session-id-resolver";
 20→import { captureTrace, type TraceData } from "./trace-writer";
 21→import {
 22→  resolveConversationHash,
 23→  type ConversationHashInput,
 24→} from "./conversation-hash-resolver";
 25→import { upsertConversation } from "./conversation-upserter";
 26→import {
 27→  evaluateProxyPolicy,
 28→  type ProxyPolicyDependencies,
 29→  type ProxyPolicyResult,
 30→  type PolicyDecisionLog,
 31→  type SpendCache,
 32→} from "./policy-evaluator";
 33→import {
 34→  createRateLimiterState,
 35→  pruneStaleEntries,
 36→  type RateLimiterState,
 37→} from "./rate-limiter";
 38→import {
 39→  loadIntelligenceConfig,
 40→  type IntelligenceConfig,
 41→} from "./intelligence-config";
 42→import {
 43→  createContextCache,
 44→  type ContextCache,
 45→  type CachedCandidatePool,
 46→  type CandidateItem,
 47→} from "./context-cache";
 48→import {
 49→  rankCandidates,
 50→  selectWithinBudget,
 51→  buildBrainContextXml,
 52→  injectBrainContext,
 53→  type ContextCandidate,
 54→  type InjectionResult,
 55→} from "./context-injector";
 56→import type { ServerDependencies } from "../runtime/types";
 57→import { RecordId } from "surrealdb";
 58→
 59→const FORWARDED_HEADERS = [
 60→  "anthropic-version",
 61→  "anthropic-beta",
 62→  "content-type",
 63→] as const;
 64→
 65→// ---------------------------------------------------------------------------
 66→// Workspace Validation (cached)
 67→// ---------------------------------------------------------------------------
 68→
 69→type WorkspaceCache = Map<string, { valid: boolean; checkedAt: number }>;
 70→
 71→const WORKSPACE_CACHE_TTL_MS = 60_000; // 1 minute
 72→
 73→async function validateWorkspace(
 74→  surreal: ServerDependencies["surreal"],
 75→  workspaceId: string,
 76→  cache: WorkspaceCache,
 77→): Promise<boolean> {
 78→  const cached = cache.get(workspaceId);
 79→  if (cached && Date.now() - cached.checkedAt < WORKSPACE_CACHE_TTL_MS) {
 80→    return cached.valid;
 81→  }
 82→
 83→  try {
 84→    const results = await surreal.query<[Array<{ id: RecordId }>]>(
 85→      `SELECT id FROM $ws;`,
 86→      { ws: new RecordId("workspace", workspaceId) },
 87→    );
 88→    const valid = (results[0]?.length ?? 0) > 0;
 89→    cache.set(workspaceId, { valid, checkedAt: Date.now() });
 90→    return valid;
 91→  } catch {
 92→    cache.set(workspaceId, { valid: false, checkedAt: Date.now() });
 93→    return false;
 94→  }
 95→}
 96→
 97→// ---------------------------------------------------------------------------
 98→// Header Forwarding
 99→// ---------------------------------------------------------------------------
100→
101→function buildUpstreamHeaders(request: Request): Headers {
102→  const headers = new Headers();
103→
104→  for (const name of FORWARDED_HEADERS) {
105→    const value = request.headers.get(name);
106→    if (value) headers.set(name, value);
107→  }
108→
109→  const xApiKey = request.headers.get("x-api-key");
110→  const authHeader = request.headers.get("authorization");
111→  if (xApiKey) headers.set("x-api-key", xApiKey);
112→  if (authHeader) headers.set("authorization", authHeader);
113→
114→  return headers;
115→}
