255→// ---------------------------------------------------------------------------
256→// Context Candidate Pool Loader (adapter boundary)
257→// ---------------------------------------------------------------------------
258→
259→const DECISION_WEIGHT = 1.0;
260→const LEARNING_WEIGHT = 0.8;
261→const OBSERVATION_WEIGHT = 0.7;
262→
263→async function loadCandidatePool(
264→  surreal: ServerDependencies["surreal"],
265→  workspaceId: string,
266→): Promise<CachedCandidatePool> {
267→  const workspaceRecord = new RecordId("workspace", workspaceId);
268→
269→  type DecisionRow = { id: RecordId; summary: string; embedding?: number[] };
270→  type LearningRow = { id: RecordId; text: string; embedding?: number[] };
271→  type ObservationRow = { id: RecordId; text: string; embedding?: number[] };
272→
273→  const [decisionResults, learningResults, observationResults] = await Promise.all([
274→    surreal.query<[DecisionRow[]]>(
275→      `SELECT id, summary, embedding FROM decision WHERE workspace = $ws AND status = 'confirmed' LIMIT 50;`,
276→      { ws: workspaceRecord },
277→    ),
278→    surreal.query<[LearningRow[]]>(
279→      `SELECT id, text, embedding FROM learning WHERE workspace = $ws AND status = 'active' LIMIT 30;`,
280→      { ws: workspaceRecord },
281→    ),
282→    surreal.query<[ObservationRow[]]>(
283→      `SELECT id, text, embedding FROM observation WHERE workspace = $ws AND status = 'open' AND severity IN ['conflict', 'warning'] LIMIT 20;`,
284→      { ws: workspaceRecord },
285→    ),
286→  ]);
287→
288→  function toCandidates<T extends { id: RecordId; embedding?: number[] }>(
289→    rows: T[],
290→    type: CandidateItem["type"],
291→    weight: number,
292→    textFn: (row: T) => string,
293→  ): CandidateItem[] {
294→    return rows.map((row) => ({
295→      id: (row.id as RecordId).id as string,
296→      type,
297→      text: textFn(row),
298→      weight,
299→      embedding: row.embedding,
300→    }));
301→  }
302→
303→  const decisions = toCandidates(decisionResults[0] ?? [], "decision", DECISION_WEIGHT, (d) => d.summary);
304→  const learnings = toCandidates(learningResults[0] ?? [], "learning", LEARNING_WEIGHT, (l) => l.text);
305→  const observations = toCandidates(observationResults[0] ?? [], "observation", OBSERVATION_WEIGHT, (o) => o.text);
306→
307→  return {
308→    decisions,
309→    learnings,
310→    observations,
311→    populatedAt: Date.now(),
312→  };
313→}
314→
315→// ---------------------------------------------------------------------------
316→// Embedding Helper (adapter boundary)
317→// ---------------------------------------------------------------------------
318→
319→async function embedUserMessage(
320→  embeddingModel: ServerDependencies["embeddingModel"],
321→  embeddingDimension: number,
322→  text: string,
323→): Promise<number[] | undefined> {
324→  try {
325→    const { embed } = await import("ai");
326→    const normalized = text.trim();
327→    if (normalized.length === 0) return undefined;
328→
329→    const result = await embed({
330→      model: embeddingModel,
331→      value: normalized,
332→    });
333→
334→    if (result.embedding.length !== embeddingDimension) return undefined;
335→    return result.embedding;
336→  } catch {
337→    return undefined;
338→  }
339→}
340→
341→// ---------------------------------------------------------------------------
342→// Context Injection Pipeline (orchestrator)
343→// ---------------------------------------------------------------------------
344→
345→type ContextInjectionResult = {
346→  readonly body: string;
347→  readonly injectionResult?: InjectionResult;
348→};
349→
350→async function runContextInjection(
351→  deps: ServerDependencies,
352→  workspaceId: string,
353→  parsedBody: ParsedBody,
354→  originalBody: string,
355→  contextCache: ContextCache,
356→  intelligenceConfig: IntelligenceConfig,
357→): Promise<ContextInjectionResult> {
358→  if (!intelligenceConfig.contextInjectionEnabled) {
359→    return { body: originalBody };
360→  }
361→
362→  // 1. Get or populate candidate pool (with cache)
363→  let pool: CachedCandidatePool;
364→  if (contextCache.has(workspaceId)) {
365→    pool = contextCache.get(workspaceId)!;
366→  } else {
367→    pool = await loadCandidatePool(deps.surreal, workspaceId);
368→    contextCache.set(workspaceId, pool);
369→  }
370→
371→  // 2. Check if pool is empty
372→  const allCandidates: ContextCandidate[] = [
373→    ...pool.decisions,
374→    ...pool.learnings,
375→    ...pool.observations,
376→  ];
377→  if (allCandidates.length === 0) {
378→    return { body: originalBody };
379→  }
380→
381→  // 3. Extract last user message for embedding
382→  const lastUserMessage = [...(parsedBody.messages ?? [])].reverse().find((m) => m.role === "user");
383→  if (!lastUserMessage) {
384→    return { body: originalBody };
385→  }
386→
387→  // 4. Embed last user message
388→  const queryEmbedding = await embedUserMessage(
389→    deps.embeddingModel,
390→    deps.config.embeddingDimension,
391→    lastUserMessage.content,
392→  );
393→
394→  let selectedCandidates;
395→  if (queryEmbedding) {
396→    // 5. Rank candidates by weighted cosine similarity
397→    const ranked = rankCandidates(allCandidates, queryEmbedding);
398→    // 6. Select within token budget
399→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
400→  } else {
401→    // No embedding available -- fall back to all candidates within budget
402→    const ranked = allCandidates.map((c) => ({
403→      id: c.id,
404→      type: c.type,
405→      text: c.text,
406→      score: c.weight,
407→    }));
408→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
409→  }
410→
411→  if (selectedCandidates.length === 0) {
412→    return { body: originalBody };
413→  }
414→
415→  // 7. Build XML block
416→  const brainContextXml = buildBrainContextXml(selectedCandidates);
417→
418→  // 8. Inject into system prompt
419→  const injectionResult = injectBrainContext(parsedBody.system, brainContextXml);
420→
421→  // 9. Build modified request body
422→  const modifiedBody = {
423→    ...parsedBody,
424→    system: injectionResult.system,
425→  };
426→
427→  return {
428→    body: JSON.stringify(modifiedBody),
429→    injectionResult,
430→  };
431→}
432→
433→// ---------------------------------------------------------------------------
434→// Intelligence Metadata Builder (pure)
435→// ---------------------------------------------------------------------------
436→
437→function buildIntelligenceMetadata(injectionResult: InjectionResult) {
438→  return {
439→    brain_context_injected: injectionResult.injected,
440→    brain_context_decisions: injectionResult.decisionsCount,
441→    brain_context_learnings: injectionResult.learningsCount,
442→    brain_context_observations: injectionResult.observationsCount,
443→    brain_context_tokens_est: injectionResult.tokensEstimated,
444→  };
445→}
