447→// ---------------------------------------------------------------------------
448→// Non-Streaming Response Content Extraction (for trace output)
449→// ---------------------------------------------------------------------------
450→
451→type ResponseContent = {
452→  content_blocks: Array<{ type: string; text?: string; id?: string; name?: string; input?: unknown }>;
453→  stop_reason: string;
454→  usage: {
455→    input_tokens: number;
456→    output_tokens: number;
457→    cache_creation_tokens?: number;
458→    cache_read_tokens?: number;
459→  };
460→};
461→
462→function extractResponseContent(responseBody: string): ResponseContent | undefined {
463→  try {
464→    const parsed = JSON.parse(responseBody);
465→    if (!parsed.content || !parsed.usage) return undefined;
466→
467→    return {
468→      content_blocks: parsed.content,
469→      stop_reason: parsed.stop_reason ?? "end_turn",
470→      usage: {
471→        input_tokens: parsed.usage.input_tokens ?? 0,
472→        output_tokens: parsed.usage.output_tokens ?? 0,
473→        cache_creation_tokens: parsed.usage.cache_creation_input_tokens,
474→        cache_read_tokens: parsed.usage.cache_read_input_tokens,
475→      },
476→    };
477→  } catch {
478→    return undefined;
479→  }
480→}
