482→// ---------------------------------------------------------------------------
483→// Policy Denial Response Builder
484→// ---------------------------------------------------------------------------
485→
486→function buildPolicyDenialResponse(
487→  result: Exclude<ProxyPolicyResult, { decision: "allow" }>,
488→): Response {
489→  if (result.decision === "deny_rate_limit") {
490→    return new Response(JSON.stringify(result.body), {
491→      status: result.status,
492→      headers: {
493→        "Content-Type": "application/json",
494→        "Retry-After": String(result.retryAfterSeconds),
495→        "Access-Control-Allow-Origin": "*",
496→      },
497→    });
498→  }
499→  return jsonResponse(result.body, result.status);
500→}
