505→
506→function buildStreamingTraceData(
507→  streamCtx: StreamContext,
508→  latencyMs: number,
509→  identitySignals: import("./identity-resolver").IdentitySignals,
510→  effectiveSessionId: string | undefined,
511→  policyDecision: PolicyDecisionLog | undefined,
