  1→/**
  2→ * Spend Monitoring Dashboard API
  3→ *
  4→ * REST endpoints for workspace spend overview and session breakdown.
  5→ * Includes anomaly detection (sessions exceeding 2x average call rate)
  6→ * and budget threshold alerts (default 80%).
  7→ *
  8→ * Ports:
  9→ *   GET /api/workspaces/:wsId/proxy/spend   -> SpendOverview
 10→ *   GET /api/workspaces/:wsId/proxy/sessions -> SessionBreakdown
 11→ *
 12→ * Pure core: aggregation transforms, anomaly detection, budget checking
 13→ * Effect boundary: SurrealDB queries, observation writes
 14→ */
 15→
 16→import { RecordId } from "surrealdb";
 17→import type { Surreal } from "surrealdb";
 18→import { jsonResponse } from "../http/response";
 19→import { logInfo, logError } from "../http/observability";
 20→import type { ServerDependencies } from "../runtime/types";
 21→
 22→// ---------------------------------------------------------------------------
 23→// Types
 24→// ---------------------------------------------------------------------------
 25→
 26→type ProjectSpendRow = {
 27→  readonly project_id: string;
 28→  readonly project_name: string;
 29→  readonly today_spend: number;
 30→  readonly mtd_spend: number;
 31→  readonly call_count: number;
 32→};
 33→
 34→type SpendOverview = {
 35→  readonly total_spend: number;
 36→  readonly daily_budget?: number;
 37→  readonly budget_progress_pct?: number;
 38→  readonly projects: ProjectSpendRow[];
 39→};
 40→
 41→type SessionRow = {
 42→  readonly session_id: string;
 43→  readonly total_cost: number;
 44→  readonly primary_model: string;
 45→  readonly call_count: number;
 46→  readonly duration_ms: number;
 47→};
 48→
 49→type SessionBreakdown = {
 50→  readonly sessions: SessionRow[];
 51→};
 52→
 53→// ---------------------------------------------------------------------------
 54→// Spend Cache (per-instance, injected)
 55→// ---------------------------------------------------------------------------
 56→
 57→type SpendCacheEntry = {
 58→  readonly data: SpendOverview;
 59→  readonly fetchedAt: number;
 60→};
 61→
 62→type SpendApiCache = Map<string, SpendCacheEntry>;
 63→
 64→const SPEND_CACHE_TTL_MS = 10_000; // 10 seconds
 65→
 66→// ---------------------------------------------------------------------------
 67→// Pure: Anomaly Detection
 68→// ---------------------------------------------------------------------------
 69→
 70→type SessionCallCount = {
 71→  readonly sessionId: string;
 72→  readonly callCount: number;
 73→};
 74→
 75→function detectAnomalySessions(
 76→  sessionCounts: readonly SessionCallCount[],
 77→): readonly SessionCallCount[] {
 78→  if (sessionCounts.length < 2) return [];
 79→
 80→  const totalCalls = sessionCounts.reduce((sum, s) => sum + s.callCount, 0);
 81→  const averageCalls = totalCalls / sessionCounts.length;
 82→  const threshold = averageCalls * 2;
 83→
 84→  return sessionCounts.filter(s => s.callCount > threshold);
 85→}
 86→
 87→// ---------------------------------------------------------------------------
 88→// Pure: Budget Threshold Check
 89→// ---------------------------------------------------------------------------
 90→
 91→const DEFAULT_ALERT_THRESHOLD = 0.80;
 92→
 93→type BudgetCheckResult =
 94→  | { readonly exceeded: false }
 95→  | { readonly exceeded: true; readonly currentSpend: number; readonly budget: number; readonly pct: number };
 96→
 97→function checkBudgetThreshold(
 98→  totalSpend: number,
 99→  dailyBudget: number | undefined,
100→): BudgetCheckResult {
101→  if (dailyBudget === undefined || dailyBudget <= 0) {
102→    return { exceeded: false };
103→  }
104→
105→  const pct = totalSpend / dailyBudget;
106→  if (pct >= DEFAULT_ALERT_THRESHOLD) {
107→    return { exceeded: true, currentSpend: totalSpend, budget: dailyBudget, pct };
108→  }
109→
110→  return { exceeded: false };
111→}
