113→// ---------------------------------------------------------------------------
114→// Query: Workspace Total Spend (today)
115→// ---------------------------------------------------------------------------
116→
117→async function queryTodayTotalSpend(
118→  surreal: Surreal,
119→  workspaceId: string,
120→): Promise<number> {
121→  const ws = new RecordId("workspace", workspaceId);
122→  const results = await surreal.query<[Array<{ cost_usd: number }>]>(
123→    `SELECT cost_usd FROM trace WHERE workspace = $ws AND created_at >= time::floor(time::now(), 1d);`,
124→    { ws },
125→  );
126→  const rows = results[0] ?? [];
127→  return rows.reduce((sum, row) => sum + (row.cost_usd ?? 0), 0);
128→}
