146→// ---------------------------------------------------------------------------
147→// Query: Per-Project Breakdown
148→// ---------------------------------------------------------------------------
149→
150→async function queryProjectBreakdown(
151→  surreal: Surreal,
152→  workspaceId: string,
153→): Promise<ProjectSpendRow[]> {
154→  const ws = new RecordId("workspace", workspaceId);
155→
156→  // Get all traces for workspace today, with their task->project attribution
157→  const results = await surreal.query<[Array<{
158→    cost_usd: number;
159→    task_projects: RecordId[];
160→    created_at: string;
161→  }>]>(
162→    `SELECT cost_usd, ->attributed_to->task->belongs_to->project AS task_projects, created_at
163→     FROM trace
164→     WHERE workspace = $ws AND created_at >= time::floor(time::now(), 30d)
165→     ORDER BY created_at DESC;`,
166→    { ws },
167→  );
168→
169→  const traces = results[0] ?? [];
170→  const todayStart = new Date();
171→  todayStart.setUTCHours(0, 0, 0, 0);
172→  const monthStart = new Date();
173→  monthStart.setUTCDate(1);
174→  monthStart.setUTCHours(0, 0, 0, 0);
175→
176→  // Aggregate by project
177→  const projectMap = new Map<string, {
178→    name: string;
179→    todaySpend: number;
180→    mtdSpend: number;
181→    callCount: number;
182→  }>();
183→
184→  // Track unattributed
185→  let unattributedTodaySpend = 0;
186→  let unattributedMtdSpend = 0;
187→  let unattributedCallCount = 0;
188→
189→  for (const trace of traces) {
190→    const traceDate = new Date(trace.created_at);
191→    const isToday = traceDate >= todayStart;
192→    const isMtd = traceDate >= monthStart;
193→    const projects = trace.task_projects ?? [];
194→
195→    if (projects.length === 0) {
196→      // Unattributed
197→      if (isToday) {
198→        unattributedTodaySpend += trace.cost_usd;
199→        unattributedCallCount++;
200→      }
201→      if (isMtd) {
202→        unattributedMtdSpend += trace.cost_usd;
203→      }
204→    } else {
205→      for (const projectRecord of projects) {
206→        const projectId = projectRecord.id as string;
207→        const existing = projectMap.get(projectId) ?? {
208→          name: projectId,
209→          todaySpend: 0,
210→          mtdSpend: 0,
211→          callCount: 0,
212→        };
213→
214→        if (isToday) {
215→          existing.todaySpend += trace.cost_usd;
216→          existing.callCount++;
217→        }
218→        if (isMtd) {
219→          existing.mtdSpend += trace.cost_usd;
220→        }
221→
222→        projectMap.set(projectId, existing);
223→      }
224→    }
225→  }
226→
227→  // Fetch project names
228→  const projectRows: ProjectSpendRow[] = [];
229→  for (const [projectId, data] of projectMap) {
230→    try {
231→      const projectRecord = new RecordId("project", projectId);
232→      const nameResults = await surreal.query<[Array<{ name: string }>]>(
233→        `SELECT name FROM $project;`,
234→        { project: projectRecord },
235→      );
236→      const name = nameResults[0]?.[0]?.name ?? projectId;
237→      projectRows.push({
238→        project_id: projectId,
239→        project_name: name,
240→        today_spend: data.todaySpend,
241→        mtd_spend: data.mtdSpend,
242→        call_count: data.callCount,
243→      });
244→    } catch {
245→      projectRows.push({
246→        project_id: projectId,
247→        project_name: projectId,
248→        today_spend: data.todaySpend,
249→        mtd_spend: data.mtdSpend,
250→        call_count: data.callCount,
251→      });
252→    }
253→  }
254→
255→  // Add unattributed if any
256→  if (unattributedCallCount > 0 || unattributedMtdSpend > 0) {
257→    projectRows.push({
258→      project_id: "unattributed",
259→      project_name: "Unattributed",
260→      today_spend: unattributedTodaySpend,
261→      mtd_spend: unattributedMtdSpend,
262→      call_count: unattributedCallCount,
263→    });
264→  }
265→
266→  // Sort by today_spend DESC
267→  projectRows.sort((a, b) => b.today_spend - a.today_spend);
268→
269→  return projectRows;
270→}
