272→// ---------------------------------------------------------------------------
273→// Query: Per-Session Breakdown
274→// ---------------------------------------------------------------------------
275→
276→async function querySessionBreakdown(
277→  surreal: Surreal,
278→  workspaceId: string,
279→): Promise<SessionRow[]> {
280→  const ws = new RecordId("workspace", workspaceId);
281→
282→  // Get all traces with session field for this workspace
283→  const results = await surreal.query<[Array<{
284→    cost_usd: number;
285→    model: string;
286→    latency_ms: number;
287→    session: RecordId | undefined;
288→    created_at: string;
289→  }>]>(
290→    `SELECT cost_usd, model, latency_ms, session, created_at
291→     FROM trace
292→     WHERE workspace = $ws AND session IS NOT NONE
293→     ORDER BY created_at DESC;`,
294→    { ws },
295→  );
296→
297→  const traces = results[0] ?? [];
298→
299→  // Aggregate by session
300→  const sessionMap = new Map<string, {
301→    totalCost: number;
302→    models: Map<string, number>;
303→    callCount: number;
304→    minCreatedAt: number;
305→    maxCreatedAt: number;
306→  }>();
307→
308→  for (const trace of traces) {
309→    if (!trace.session) continue;
310→    const sessionId = trace.session.id as string;
311→    const existing = sessionMap.get(sessionId) ?? {
312→      totalCost: 0,
313→      models: new Map(),
314→      callCount: 0,
315→      minCreatedAt: Infinity,
316→      maxCreatedAt: 0,
317→    };
318→
319→    existing.totalCost += trace.cost_usd;
320→    existing.callCount++;
321→    existing.models.set(
322→      trace.model,
323→      (existing.models.get(trace.model) ?? 0) + 1,
324→    );
325→
326→    const traceTime = new Date(trace.created_at).getTime();
327→    existing.minCreatedAt = Math.min(existing.minCreatedAt, traceTime);
328→    existing.maxCreatedAt = Math.max(existing.maxCreatedAt, traceTime);
329→
330→    sessionMap.set(sessionId, existing);
331→  }
332→
333→  // Convert to rows
334→  const sessionRows: SessionRow[] = [];
335→  for (const [sessionId, data] of sessionMap) {
336→    // Primary model = most used model
337→    let primaryModel = "unknown";
338→    let maxCount = 0;
339→    for (const [model, count] of data.models) {
340→      if (count > maxCount) {
341→        maxCount = count;
342→        primaryModel = model;
343→      }
344→    }
345→
346→    const durationMs = data.maxCreatedAt > data.minCreatedAt
347→      ? data.maxCreatedAt - data.minCreatedAt
348→      : 0;
349→
350→    sessionRows.push({
351→      session_id: sessionId,
352→      total_cost: data.totalCost,
353→      primary_model: primaryModel,
354→      call_count: data.callCount,
355→      duration_ms: durationMs,
356→    });
357→  }
358→
359→  // Sort by cost DESC
360→  sessionRows.sort((a, b) => b.total_cost - a.total_cost);
361→
362→  return sessionRows;
363→}
