365→// ---------------------------------------------------------------------------
366→// Query: Session Call Counts (for anomaly detection)
367→// ---------------------------------------------------------------------------
368→
369→async function querySessionCallCounts(
370→  surreal: Surreal,
371→  workspaceId: string,
372→): Promise<SessionCallCount[]> {
373→  const ws = new RecordId("workspace", workspaceId);
374→
375→  // Get traces with session field for today
376→  const results = await surreal.query<[Array<{
377→    session: RecordId | undefined;
378→  }>]>(
379→    `SELECT session
380→     FROM trace
381→     WHERE workspace = $ws AND session IS NOT NONE AND created_at >= time::floor(time::now(), 1d);`,
382→    { ws },
383→  );
384→
385→  const traces = results[0] ?? [];
386→  const sessionCounts = new Map<string, number>();
387→
388→  for (const trace of traces) {
389→    if (!trace.session) continue;
390→    const sessionId = trace.session.id as string;
391→    sessionCounts.set(sessionId, (sessionCounts.get(sessionId) ?? 0) + 1);
392→  }
393→
394→  return Array.from(sessionCounts.entries()).map(([sessionId, callCount]) => ({
395→    sessionId,
396→    callCount,
397→  }));
398→}
