400→// ---------------------------------------------------------------------------
401→// Observation Writers (async, fire-and-forget)
402→// ---------------------------------------------------------------------------
403→
404→async function createAnomalyObservation(
405→  surreal: Surreal,
406→  workspaceId: string,
407→  session: SessionCallCount,
408→  averageCalls: number,
409→): Promise<void> {
410→  const observationId = `obs-${crypto.randomUUID()}`;
411→  const observationRecord = new RecordId("observation", observationId);
412→  const workspaceRecord = new RecordId("workspace", workspaceId);
413→
414→  await surreal.query(`CREATE $obs CONTENT $content;`, {
415→    obs: observationRecord,
416→    content: {
417→      text: `Session ${session.sessionId} has ${session.callCount} LLM calls today, which is ${(session.callCount / averageCalls).toFixed(1)}x the average of ${averageCalls.toFixed(0)} calls per session. This may indicate runaway agent behavior or an infinite loop.`,
418→      severity: "warning",
419→      status: "open",
420→      observation_type: "anomaly",
421→      source_agent: "llm-proxy",
422→      workspace: workspaceRecord,
423→      data: { subtype: "proxy_anomaly_call_rate" },
424→      created_at: new Date(),
425→    },
426→  });
427→}
