429→async function createBudgetThresholdObservation(
430→  surreal: Surreal,
431→  workspaceId: string,
432→  currentSpend: number,
433→  budget: number,
434→  pct: number,
435→): Promise<void> {
436→  const observationId = `obs-${crypto.randomUUID()}`;
437→  const observationRecord = new RecordId("observation", observationId);
438→  const workspaceRecord = new RecordId("workspace", workspaceId);
439→
440→  await surreal.query(`CREATE $obs CONTENT $content;`, {
441→    obs: observationRecord,
442→    content: {
443→      text: `Daily spend has reached $${currentSpend.toFixed(2)} (${(pct * 100).toFixed(0)}% of $${budget.toFixed(2)} budget). Consider reviewing active agent sessions or adjusting the daily budget limit.`,
444→      severity: "warning",
445→      status: "open",
446→      observation_type: "anomaly",
447→      source_agent: "llm-proxy",
448→      workspace: workspaceRecord,
449→      data: { subtype: "proxy_budget_threshold" },
450→      created_at: new Date(),
451→    },
452→  });
453→}
