455→// ---------------------------------------------------------------------------
456→// Check if observation already exists today (dedup)
457→// ---------------------------------------------------------------------------
458→
459→async function hasObservationToday(
460→  surreal: Surreal,
461→  workspaceId: string,
462→  subtype: string,
463→): Promise<boolean> {
464→  const ws = new RecordId("workspace", workspaceId);
465→  const results = await surreal.query<[Array<{ id: RecordId }>]>(
466→    `SELECT id FROM observation WHERE workspace = $ws AND source_agent = 'llm-proxy' AND data.subtype = $subtype AND created_at >= time::floor(time::now(), 1d) LIMIT 1;`,
