472→// ---------------------------------------------------------------------------
473→// Spend Handler (composing queries + anomaly + budget checks)
474→// ---------------------------------------------------------------------------
475→
476→async function buildSpendOverview(
477→  surreal: Surreal,
478→  workspaceId: string,
479→): Promise<SpendOverview> {
480→  const [totalSpend, dailyBudget, projects] = await Promise.all([
481→    queryTodayTotalSpend(surreal, workspaceId),
482→    queryDailyBudget(surreal, workspaceId),
483→    queryProjectBreakdown(surreal, workspaceId),
484→  ]);
485→
486→  const budgetProgressPct = dailyBudget && dailyBudget > 0
487→    ? (totalSpend / dailyBudget) * 100
488→    : undefined;
489→
490→  return {
491→    total_spend: totalSpend,
492→    daily_budget: dailyBudget,
493→    budget_progress_pct: budgetProgressPct,
494→    projects,
495→  };
496→}
