498→// ---------------------------------------------------------------------------
499→// Route Handler Factory
500→// ---------------------------------------------------------------------------
501→
502→export type SpendApiHandlers = {
503→  readonly handleSpend: (workspaceId: string) => Promise<Response>;
504→  readonly handleSessions: (workspaceId: string) => Promise<Response>;
505→};
506→
507→export function createSpendApiHandlers(deps: ServerDependencies): SpendApiHandlers {
508→  const spendCache: SpendApiCache = new Map();
509→
510→  const handleSpend = async (workspaceId: string): Promise<Response> => {
511→    try {
512→      // Check cache
513→      const now = Date.now();
514→      const cached = spendCache.get(workspaceId);
515→      let overview: SpendOverview;
516→
517→      if (cached && now - cached.fetchedAt < SPEND_CACHE_TTL_MS) {
518→        overview = cached.data;
519→      } else {
520→        overview = await buildSpendOverview(deps.surreal, workspaceId);
521→        spendCache.set(workspaceId, { data: overview, fetchedAt: Date.now() });
522→      }
523→
524→      // Async: anomaly detection
525→      deps.inflight.track(
526→        runAnomalyDetection(deps.surreal, workspaceId).catch((err) => {
527→          logError("proxy.spend.anomaly_detection_failed", "Anomaly detection failed", err);
528→        }),
529→      );
530→
531→      // Async: budget threshold check
532→      if (overview.daily_budget !== undefined) {
533→        const budgetCheck = checkBudgetThreshold(overview.total_spend, overview.daily_budget);
534→        if (budgetCheck.exceeded) {
535→          deps.inflight.track(
536→            createBudgetThresholdObservationIfNew(
537→              deps.surreal,
538→              workspaceId,
539→              budgetCheck.currentSpend,
540→              budgetCheck.budget,
541→              budgetCheck.pct,
542→            ).catch((err) => {
543→              logError("proxy.spend.budget_alert_failed", "Budget alert creation failed", err);
544→            }),
545→          );
546→        }
547→      }
548→
549→      return jsonResponse(overview, 200);
550→    } catch (error) {
551→      logError("proxy.spend.query_failed", "Failed to build spend overview", error);
552→      return jsonResponse({ error: "spend_query_failed" }, 500);
553→    }
554→  };
555→
556→  const handleSessions = async (workspaceId: string): Promise<Response> => {
557→    try {
558→      const sessions = await querySessionBreakdown(deps.surreal, workspaceId);
559→      const breakdown: SessionBreakdown = { sessions };
560→      return jsonResponse(breakdown, 200);
561→    } catch (error) {
562→      logError("proxy.sessions.query_failed", "Failed to build session breakdown", error);
563→      return jsonResponse({ error: "session_query_failed" }, 500);
564→    }
565→  };
566→
567→  return { handleSpend, handleSessions };
568→}
