// Intelligence: Observer Trigger Helpers
// ---------------------------------------------------------------------------

/**
 * Trigger the Observer coherence scan for a workspace.
 */
export async function triggerCoherenceScan(
  baseUrl: string,
  workspaceId: string,
): Promise<Response> {
  return fetch(
    `${baseUrl}/api/observe/scan/${workspaceId}`,
    { method: "POST" },
  );
}

