  2→ * Acceptance Tests: LLM Proxy Walking Skeletons
  3→ *
  4→ * Three thinnest E2E slices proving observable user value:
  5→ * 1. Passthrough — developer's LLM call works identically through proxy
  6→ * 2. Trace capture — LLM call recorded as trace in knowledge graph
  7→ * 3. Cost attribution — admin sees cost attributed to correct project
  8→ *
  9→ * Each skeleton builds on the previous. Implement in order.
 10→ * Driving port: POST /proxy/llm/anthropic/v1/messages
 11→ */
 12→import { describe, expect, it } from "bun:test";
 13→import {
 14→  setupAcceptanceSuite,
 15→  sendProxyRequest,
 16→  createProxyTestWorkspace,
 17→  createProxyTestProject,
 18→  createProxyTestTask,
 19→  getTracesForWorkspace,
 20→  getTracesForTask,
 21→  getWorkspaceSpend,
 22→} from "./llm-proxy-test-kit";
 23→
 24→const getRuntime = setupAcceptanceSuite("llm_proxy_skeleton");
 25→
 26→// ---------------------------------------------------------------------------
 27→// Skeleton 1: Developer makes an LLM call through the proxy and it works
 28→// ---------------------------------------------------------------------------
 29→describe("Skeleton 1: Non-streaming passthrough", () => {
 30→  it("forwards a request and returns the model response identically", async () => {
 31→    const { baseUrl } = getRuntime();
 32→
 33→    // Given Priya has configured Claude Code to use Brain's proxy
 34→    // And she has a valid Anthropic API key
 35→    const response = await sendProxyRequest(baseUrl, {
 36→      model: "claude-sonnet-4-20250514",
 37→      stream: false,
 38→      maxTokens: 50,
 39→      messages: [{ role: "user", content: "Reply with exactly the word 'hello'." }],
 40→      apiKey: process.env.OPENROUTER_API_KEY ?? process.env.ANTHROPIC_API_KEY,
