247→// ---------------------------------------------------------------------------
248→// SSE Helpers
249→// ---------------------------------------------------------------------------
250→
251→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
252→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
253→  if (!response.ok || !response.body) {
254→    throw new Error(`Failed to open SSE stream (${response.status})`);
255→  }
256→
257→  const reader = response.body.getReader();
258→  const decoder = new TextDecoder();
259→  const events: T[] = [];
260→  let buffer = "";
261→
262→  const timeout = setTimeout(() => {
263→    void reader.cancel();
264→  }, timeoutMs);
265→
266→  try {
267→    while (true) {
268→      const { value, done } = await reader.read();
269→      if (done) {
270→        break;
271→      }
272→
273→      buffer += decoder.decode(value, { stream: true });
274→      const segments = buffer.split("\n\n");
275→      buffer = segments.pop() ?? "";
276→
277→      for (const segment of segments) {
278→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
279→        if (!dataLine) {
280→          continue;
281→        }
282→
283→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
284→        events.push(event);
285→
286→        if (event.type === "error") {
287→          const errorText = (event as { error?: string }).error;
288→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
289→        }
290→
291→        if (event.type === "done") {
292→          return events;
293→        }
294→      }
295→    }
296→  } finally {
297→    clearTimeout(timeout);
298→    reader.releaseLock();
299→  }
300→
301→  return events;
302→}
