336→/**
337→ * Obtain an OAuth2 JWT access token for MCP endpoints.
338→ * Requires a SurrealDB connection to skip consent screen.
339→ */
340→export async function getOAuthToken(
341→  baseUrl: string,
342→  surreal: Surreal,
343→  sessionHeaders: Record<string, string>,
344→  scopes: string = "graph:read graph:reason session:write offline_access",
345→): Promise<string> {
346→  // Trigger JWKS key generation if not yet done
347→  await fetch(`${baseUrl}/api/auth/jwks`);
348→
349→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
350→    method: "POST",
351→    headers: { "Content-Type": "application/json" },
352→    body: JSON.stringify({
353→      client_name: `test-client-${Date.now()}`,
354→      redirect_uris: ["http://127.0.0.1:9999/callback"],
355→      grant_types: ["authorization_code", "refresh_token"],
356→      response_types: ["code"],
357→      token_endpoint_auth_method: "none",
358→    }),
359→  });
360→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
361→
362→  const { client_id } = (await dcrRes.json()) as { client_id: string };
363→
364→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
365→    cid: client_id,
366→  });
367→
368→  const { verifier, challenge } = generatePkce();
369→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
370→  authUrl.searchParams.set("client_id", client_id);
371→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
372→  authUrl.searchParams.set("response_type", "code");
373→  authUrl.searchParams.set("scope", scopes);
374→  authUrl.searchParams.set("state", "test-state");
375→  authUrl.searchParams.set("code_challenge", challenge);
376→  authUrl.searchParams.set("code_challenge_method", "S256");
377→  authUrl.searchParams.set("resource", baseUrl);
378→
379→  const authRes = await fetch(authUrl.toString(), {
380→    headers: sessionHeaders,
381→    redirect: "manual",
382→  });
383→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
384→
385→  const location = authRes.headers.get("location")!;
386→  const redirectUrl = new URL(location, baseUrl);
387→  const code = redirectUrl.searchParams.get("code") ?? "";
388→  if (!code) throw new Error(`No code in redirect: ${location}`);
389→
390→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
391→    method: "POST",
392→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
393→    body: new URLSearchParams({
394→      grant_type: "authorization_code",
395→      code,
396→      redirect_uri: "http://127.0.0.1:9999/callback",
397→      client_id,
398→      code_verifier: verifier,
399→      resource: baseUrl,
400→    }),
401→  });
402→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
403→
404→  const tokens = (await tokenRes.json()) as { access_token: string };
405→  return tokens.access_token;
406→}
