501→    { type: "brain_action", action: "create", resource: "commit" },
502→    { type: "brain_action", action: "create", resource: "intent" },
503→    { type: "brain_action", action: "update", resource: "task" },
504→    { type: "brain_action", action: "update", resource: "session" },
505→    { type: "brain_action", action: "update", resource: "suggestion" },
506→    { type: "brain_action", action: "submit", resource: "intent" },
507→  ];
508→
509→  const intentId = `test-intent-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
510→  const intentRecord = new RecordId("intent", intentId);
511→  const traceRecord = new RecordId("trace", `trace-${intentId}`);
512→
513→  await surreal.query(`CREATE $trace CONTENT $traceContent;`, {
514→    trace: traceRecord,
515→    traceContent: { type: "intent_submission", actor: identityRecord, workspace: workspaceRecord, created_at: new Date() },
516→  });
517→
518→  await surreal.query(`CREATE $intent CONTENT $content;`, {
519→    intent: intentRecord,
520→    content: {
521→      goal: "Broad test access",
522→      reasoning: "Pre-authorized for acceptance testing",
523→      status: "authorized",
524→      priority: 50,
525→      authorization_details: broadActions,
526→      dpop_jwk_thumbprint: keyPair.thumbprint,
527→      action_spec: { provider: "test", action: "broad_access", params: {} },
528→      trace_id: traceRecord,
529→      requester: identityRecord,
530→      workspace: workspaceRecord,
531→      evaluation: {
532→        decision: "APPROVE",
533→        risk_score: 0,
534→        reason: "Pre-authorized for testing",
535→        evaluated_at: new Date(),
536→        policy_only: true,
537→      },
538→      created_at: new Date(),
539→    },
540→  });
541→
542→  // Request DPoP-bound access token from Custom AS
543→  const tokenUri = `${baseUrl}/api/auth/token`;
544→  const dpopProof = await createDPoPProof(keyPair, "POST", tokenUri);
545→
546→  const tokenRes = await fetch(tokenUri, {
547→    method: "POST",
548→    headers: {
549→      "Content-Type": "application/json",
550→      DPoP: dpopProof,
551→    },
552→    body: JSON.stringify({
553→      grant_type: "urn:brain:intent-authorization",
554→      intent_id: intentId,
555→      authorization_details: broadActions,
556→    }),
557→  });
558→
559→  if (!tokenRes.ok) {
560→    const body = await tokenRes.text();
561→    throw new Error(`DPoP token acquisition failed (${tokenRes.status}): ${body}`);
562→  }
563→
564→  const { access_token } = (await tokenRes.json()) as { access_token: string };
565→
566→  const mcpFetch = async (path: string, options?: { method?: string; body?: unknown }): Promise<Response> => {
567→    const method = options?.method ?? "POST";
568→    const requestUri = `${baseUrl}${path}`;
569→    const proof = await createDPoPProof(keyPair, method, requestUri);
570→
571→    return fetch(requestUri, {
572→      method,
573→      headers: {
574→        "Content-Type": "application/json",
575→        Authorization: `DPoP ${access_token}`,
576→        DPoP: proof,
577→      },
578→      body: options?.body !== undefined ? JSON.stringify(options.body) : JSON.stringify({}),
579→    });
580→  };
581→
582→  return {
583→    ...user,
584→    mcpHeaders: { Authorization: `DPoP ${access_token}` },
585→    mcpFetch,
586→    accessToken: access_token,
587→    keyPair,
588→    workspaceId,
589→    identityId,
590→  };
591→}
592→
593→// ---------------------------------------------------------------------------
594→// DPoP Helpers
595→// ---------------------------------------------------------------------------
596→
597→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
598→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
599→    { name: "ECDSA", namedCurve: "P-256" },
600→    true,
601→    ["sign", "verify"],
602→  );
603→
604→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
605→  const thumbprint = await computeDPoPThumbprint(publicJwk);
606→
607→  return { privateKey, publicKey, publicJwk, thumbprint };
608→}
609→
610→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
611→  const thumbprintInput = JSON.stringify({
612→    crv: publicJwk.crv,
613→    kty: publicJwk.kty,
614→    x: publicJwk.x,
615→    y: publicJwk.y,
616→  });
617→
618→  const hashBuffer = await crypto.subtle.digest(
619→    "SHA-256",
620→    new TextEncoder().encode(thumbprintInput),
621→  );
622→
623→  return base64urlBytes(new Uint8Array(hashBuffer));
624→}
625→
626→async function createDPoPProof(
627→  keyPair: DPoPKeyPair,
628→  method: string,
629→  targetUri: string,
630→): Promise<string> {
631→  const header = {
632→    typ: "dpop+jwt" as const,
633→    alg: "ES256" as const,
634→    jwk: {
635→      kty: keyPair.publicJwk.kty,
636→      crv: keyPair.publicJwk.crv,
637→      x: keyPair.publicJwk.x,
638→      y: keyPair.publicJwk.y,
639→    },
640→  };
641→
642→  const payload = {
643→    jti: crypto.randomUUID(),
644→    htm: method,
645→    htu: targetUri,
646→    iat: Math.floor(Date.now() / 1000),
647→  };
648→
649→  const importedKey = await jose.importJWK(
650→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
651→    "ES256",
652→  );
653→
654→  return await new jose.SignJWT(payload)
655→    .setProtectedHeader(header)
656→    .sign(importedKey);
657→}
658→
659→function base64urlBytes(bytes: Uint8Array): string {
660→  const binary = String.fromCharCode(...bytes);
661→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
662→}
663→
664→// ---------------------------------------------------------------------------
665→// Internal Utilities
666→// ---------------------------------------------------------------------------
667→
668→function requireTestEnv(name: string): string {
669→  const value = process.env[name];
670→  if (!value || value.trim().length === 0) {
671→    throw new Error(`Acceptance test requires env var ${name}`);
672→  }
673→  return value;
674→}
675→
676→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
677→  return await Promise.race([
678→    callback(),
679→    new Promise<T>((_, reject) => {
680→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
681→    }),
682→  ]);
683→}
