 86→describe("Claude Code metadata.user_id session extraction", () => {
 87→  it("links the trace to the agent session resolved from Claude Code metadata", async () => {
 88→    const { baseUrl, surreal } = getRuntime();
 89→
 90→    const workspaceId = `ws-sess-cc-${crypto.randomUUID()}`;
 91→    const ccSessionId = crypto.randomUUID();
 92→    await createProxyTestWorkspace(surreal, workspaceId);
 93→
 94→    // Given an agent session was created by the CLI with Claude Code's session ID
 95→    await seedAgentSession(surreal, crypto.randomUUID(), {
 96→      workspaceId,
 97→      agent: "coding-agent",
 98→      source: "proxy",
 99→      externalSessionId: ccSessionId,
100→    });
101→
102→    // When Claude Code sends a request with session ID embedded in metadata.user_id
103→    const response = await sendProxyRequest(baseUrl, {
104→      model: "claude-sonnet-4-20250514",
105→      stream: false,
106→      maxTokens: 50,
107→      messages: [{ role: "user", content: "Hello" }],
108→      apiKey: process.env.OPENROUTER_API_KEY ?? process.env.ANTHROPIC_API_KEY,
109→      workspaceHeader: workspaceId,
110→      metadata: {
111→        user_id: buildClaudeCodeUserId("a1b2c3", "acct-123", ccSessionId),
112→      },
113→    });
114→
115→    expect(response.status).toBe(200);
116→    await response.json();
117→
118→    await new Promise(resolve => setTimeout(resolve, 2000));
119→
120→    // Then the trace is linked to the agent session
121→    const traces = await getTracesForWorkspace(surreal, workspaceId);
122→    expect(traces.length).toBeGreaterThanOrEqual(1);
123→
124→    const traceId = traces[0].id.id as string;
125→    const edges = await getTraceEdges(surreal, traceId);
126→    expect(edges.sessions.length).toBeGreaterThanOrEqual(1);
127→  }, 30_000);
128→});
129→
130→describe("Unknown client — trace linked to workspace only", () => {
131→  it("creates a trace with workspace edge but no session edge for unidentified clients", async () => {
132→    const { baseUrl, surreal } = getRuntime();
133→
134→    const workspaceId = `ws-sess-unknown-${crypto.randomUUID()}`;
135→    await createProxyTestWorkspace(surreal, workspaceId);
136→
137→    // Given no session ID is provided in the request (no header, no metadata)
138→    const response = await sendProxyRequest(baseUrl, {
139→      model: "claude-sonnet-4-20250514",
140→      stream: false,
141→      maxTokens: 50,
142→      messages: [{ role: "user", content: "Hello" }],
143→      apiKey: process.env.OPENROUTER_API_KEY ?? process.env.ANTHROPIC_API_KEY,
144→      workspaceHeader: workspaceId,
145→      // No metadata, no session header
146→    });
147→
148→    expect(response.status).toBe(200);
149→    await response.json();
150→
151→    await new Promise(resolve => setTimeout(resolve, 2000));
152→
153→    // Then the trace has a workspace edge but no session edge
154→    const traces = await getTracesForWorkspace(surreal, workspaceId);
155→    expect(traces.length).toBeGreaterThanOrEqual(1);
156→
157→    const traceId = traces[0].id.id as string;
158→    const edges = await getTraceEdges(surreal, traceId);
159→    expect(edges.workspaces.length).toBeGreaterThanOrEqual(1);
160→    expect(edges.sessions).toHaveLength(0);
161→  }, 30_000);
162→});
