content.content:
  1→/**
  2→ * Context Injector -- Pure functions for brain-context injection
  3→ *
  4→ * Responsible for:
  5→ * 1. Ranking context candidates by weighted cosine similarity
  6→ * 2. Selecting top N within token budget
  7→ * 3. Building <brain-context> XML block
  8→ * 4. Injecting into system prompt (string or array form)
  9→ *
 10→ * All functions are pure -- no IO, no side effects.
 11→ * The orchestration (embedding, cache, DB queries) lives in the proxy route.
 12→ */
 13→
 14→// ---------------------------------------------------------------------------
 15→// Types
 16→// ---------------------------------------------------------------------------
 17→
 18→export type ContextCandidate = {
 19→  readonly id: string;
 20→  readonly type: "decision" | "learning" | "observation";
 21→  readonly text: string;
 22→  readonly embedding?: number[];
 23→  readonly weight: number;
 24→};
 25→
 26→export type RankedCandidate = {
 27→  readonly id: string;
 28→  readonly type: "decision" | "learning" | "observation";
 29→  readonly text: string;
 30→  readonly score: number;
 31→};
 32→
 33→export type InjectionResult = {
 34→  readonly system: string | Array<{ type: string; text: string; cache_control?: { type: string } }>;
 35→  readonly injected: boolean;
 36→  readonly tokensEstimated: number;
 37→  readonly decisionsCount: number;
 38→  readonly learningsCount: number;
 39→  readonly observationsCount: number;
 40→};
 41→
 42→type SystemPrompt = string | Array<{ type: string; text: string; cache_control?: { type: string } }> | undefined;
 43→
 44→// ---------------------------------------------------------------------------
 45→// Cosine Similarity (pure)
 46→// ---------------------------------------------------------------------------
 47→
 48→function cosineSimilarity(a: number[], b: number[]): number {
 49→  if (a.length !== b.length || a.length === 0) return 0;
 50→
 51→  let dotProduct = 0;
 52→  let normA = 0;
 53→  let normB = 0;
 54→
 55→  for (let i = 0; i < a.length; i++) {
 56→    dotProduct += a[i] * b[i];
 57→    normA += a[i] * a[i];
 58→    normB += b[i] * b[i];
 59→  }
 60→
 61→  const denominator = Math.sqrt(normA) * Math.sqrt(normB);
 62→  if (denominator === 0) return 0;
 63→
 64→  return dotProduct / denominator;
 65→}
 66→
 67→// ---------------------------------------------------------------------------
 68→// Token Estimation (pure, ~4 chars per token)
 69→// ---------------------------------------------------------------------------
 70→
 71→export function estimateTokenCount(text: string): number {
 72→  return Math.ceil(text.length / 4);
 73→}
 74→
 75→// ---------------------------------------------------------------------------
 76→// Ranking: weighted cosine similarity
 77→// ---------------------------------------------------------------------------
 78→
 79→export function rankCandidates(
 80→  candidates: ContextCandidate[],
 81→  queryEmbedding: number[],
 82→): RankedCandidate[] {
 83→  return candidates
 84→    .map((c) => {
 85→      // Candidates with embeddings get similarity-weighted scores;
 86→      // candidates without embeddings fall back to a baseline weight
 87→      // (half their type weight) so they're still included but ranked lower.
 88→      const hasEmbedding = c.embedding !== undefined && c.embedding.length > 0;
 89→      const score = hasEmbedding
 90→        ? cosineSimilarity(c.embedding!, queryEmbedding) * c.weight
 91→        : c.weight * 0.5;
 92→      return { id: c.id, type: c.type, text: c.text, score };
 93→    })
 94→    .sort((a, b) => b.score - a.score);
 95→}
 96→
 97→// ---------------------------------------------------------------------------
 98→// Budget Selection: top N within token budget
 99→// ---------------------------------------------------------------------------
100→
101→export function selectWithinBudget(
102→  ranked: RankedCandidate[],
103→  tokenBudget: number,
104→): RankedCandidate[] {
105→  const selected: RankedCandidate[] = [];
106→  let tokensUsed = 0;
107→
108→  for (const candidate of ranked) {
109→    const candidateTokens = estimateTokenCount(candidate.text);
110→    if (tokensUsed + candidateTokens > tokenBudget) break;
111→    selected.push(candidate);
112→    tokensUsed += candidateTokens;
113→  }
114→
115→  return selected;
116→}
117→
118→// ---------------------------------------------------------------------------
119→// XML Block Construction
120→// ---------------------------------------------------------------------------
121→
122→export function buildBrainContextXml(selected: RankedCandidate[]): string {
123→  if (selected.length === 0) return "";
124→
125→  const decisions = selected.filter((c) => c.type === "decision");
126→  const learnings = selected.filter((c) => c.type === "learning");
127→  const observations = selected.filter((c) => c.type === "observation");
128→
129→  const sections: string[] = [];
130→
131→  if (decisions.length > 0) {
132→    const items = decisions.map((d) => `  <item>${d.text}</item>`).join("\n");
133→    sections.push(`<decisions>\n${items}\n</decisions>`);
134→  }
135→
136→  if (learnings.length > 0) {
137→    const items = learnings.map((l) => `  <item>${l.text}</item>`).join("\n");
138→    sections.push(`<learnings>\n${items}\n</learnings>`);
139→  }
140→
141→  if (observations.length > 0) {
142→    const items = observations.map((o) => `  <item>${o.text}</item>`).join("\n");
143→    sections.push(`<observations>\n${items}\n</observations>`);
144→  }
145→
146→  return `<brain-context>\n${sections.join("\n")}\n</brain-context>`;
147→}
148→
149→// ---------------------------------------------------------------------------
150→// System Prompt Injection
151→// ---------------------------------------------------------------------------
152→
153→export function injectBrainContext(
154→  originalSystem: SystemPrompt,
155→  brainContextXml: string,
156→): InjectionResult {
157→  if (!brainContextXml) {
158→    return {
159→      system: originalSystem ?? "",
160→      injected: false,
161→      tokensEstimated: 0,
162→      decisionsCount: 0,
163→      learningsCount: 0,
164→      observationsCount: 0,
165→    };
166→  }
167→
