  1→/**
  2→ * Anthropic LLM Proxy Route
  3→ *
  4→ * Transparent proxy that forwards requests to Anthropic's Messages API
  5→ * with identity resolution, session tracking, and workspace validation.
  6→ *
  7→ * Pipeline execution order:
  8→ * 1. Identity resolution (from metadata + headers)
  9→ * 2. Session ID resolution (header priority over metadata)
 10→ * 3. Conversation hash (03-01) — deterministic UUIDv5 from content
 11→ * 4. Policy evaluation [future 02-01]
 12→ * 5. Context injection [future 03-02]
 13→ * 6. Request forwarding
 14→ * 7. Async trace capture (01-03) + conversation upsert
 15→ */
 16→import { logInfo, logError, logWarn, elapsedMs } from "../http/observability";
 17→import { jsonResponse } from "../http/response";
 18→import { resolveIdentity } from "./identity-resolver";
 19→import { resolveSessionId } from "./session-id-resolver";
 20→import { captureTrace, type TraceData } from "./trace-writer";
 21→import {
 22→  resolveConversationHash,
 23→  type ConversationHashInput,
 24→} from "./conversation-hash-resolver";
 25→import { upsertConversation } from "./conversation-upserter";
 26→import {
 27→  evaluateProxyPolicy,
 28→  type ProxyPolicyDependencies,
 29→  type ProxyPolicyResult,
 30→  type PolicyDecisionLog,
 31→  type SpendCache,
 32→} from "./policy-evaluator";
 33→import {
 34→  createRateLimiterState,
 35→  pruneStaleEntries,
 36→  type RateLimiterState,
 37→} from "./rate-limiter";
 38→import {
 39→  loadIntelligenceConfig,
 40→  type IntelligenceConfig,
 41→} from "./intelligence-config";
 42→import {
 43→  createContextCache,
 44→  type ContextCache,
 45→  type CachedCandidatePool,
 46→  type CandidateItem,
 47→} from "./context-cache";
 48→import {
 49→  rankCandidates,
 50→  selectWithinBudget,
 51→  buildBrainContextXml,
 52→  injectBrainContext,
 53→  type ContextCandidate,
 54→  type InjectionResult,
 55→} from "./context-injector";
 56→import type { ServerDependencies } from "../runtime/types";
 57→import { RecordId } from "surrealdb";
 58→
 59→const FORWARDED_HEADERS = [
 60→  "anthropic-version",
 61→  "anthropic-beta",
 62→  "content-type",
 63→] as const;
 64→
 65→// ---------------------------------------------------------------------------
 66→// Workspace Validation (cached)
 67→// ---------------------------------------------------------------------------
 68→
 69→type WorkspaceCache = Map<string, { valid: boolean; checkedAt: number }>;
 70→
 71→const WORKSPACE_CACHE_TTL_MS = 60_000; // 1 minute
 72→
 73→async function validateWorkspace(
 74→  surreal: ServerDependencies["surreal"],
 75→  workspaceId: string,
 76→  cache: WorkspaceCache,
 77→): Promise<boolean> {
 78→  const cached = cache.get(workspaceId);
 79→  if (cached && Date.now() - cached.checkedAt < WORKSPACE_CACHE_TTL_MS) {
 80→    return cached.valid;
 81→  }
 82→
 83→  try {
 84→    const results = await surreal.query<[Array<{ id: RecordId }>]>(
 85→      `SELECT id FROM $ws;`,
 86→      { ws: new RecordId("workspace", workspaceId) },
 87→    );
 88→    const valid = (results[0]?.length ?? 0) > 0;
 89→    cache.set(workspaceId, { valid, checkedAt: Date.now() });
 90→    return valid;
 91→  } catch {
 92→    cache.set(workspaceId, { valid: false, checkedAt: Date.now() });
 93→    return false;
 94→  }
 95→}
 96→
 97→// ---------------------------------------------------------------------------
 98→// Header Forwarding
 99→// ---------------------------------------------------------------------------
100→
101→function buildUpstreamHeaders(request: Request): Headers {
102→  const headers = new Headers();
103→
104→  for (const name of FORWARDED_HEADERS) {
105→    const value = request.headers.get(name);
106→    if (value) headers.set(name, value);
107→  }
108→
109→  const xApiKey = request.headers.get("x-api-key");
110→  const authHeader = request.headers.get("authorization");
111→  if (xApiKey) headers.set("x-api-key", xApiKey);
112→  if (authHeader) headers.set("authorization", authHeader);
113→
114→  return headers;
115→}
116→
117→// ---------------------------------------------------------------------------
118→// Request Body Parsing
119→// ---------------------------------------------------------------------------
120→
121→type ParsedBody = {
122→  model?: string;
123→  stream?: boolean;
124→  max_tokens?: number;
125→  metadata?: { user_id?: string };
126→  system?: string | Array<{ type: string; text: string }>;
127→  messages?: Array<{ role: string; content: string }>;
128→};
129→
130→function tryParseRequestBody(body: string): ParsedBody | undefined {
131→  try {
132→    return JSON.parse(body) as ParsedBody;
133→  } catch {
134→    return undefined;
135→  }
136→}
137→
138→// ---------------------------------------------------------------------------
139→// Path Detection
140→// ---------------------------------------------------------------------------
141→
142→function isCountTokensRequest(pathname: string): boolean {
143→  return pathname.endsWith("/count_tokens");
144→}
145→
146→// ---------------------------------------------------------------------------
147→// SSE Usage Extraction
148→// ---------------------------------------------------------------------------
149→
150→type StreamContext = {
151→  model?: string;
152→  inputTokens: number;
153→  outputTokens: number;
154→  cacheCreationTokens: number;
155→  cacheReadTokens: number;
156→  stopReason?: string;
157→};
158→
159→function extractSSEUsage(buffer: string, ctx: StreamContext): string {
160→  const lines = buffer.split("\n");
161→  const remainder = lines.pop() ?? "";
162→
163→  for (const line of lines) {
164→    if (!line.startsWith("data: ")) continue;
165→    const data = line.slice(6);
166→    if (data === "[DONE]") continue;
167→
168→    try {
169→      const event = JSON.parse(data);
170→
171→      if (event.type === "message_start" && event.message?.usage) {
172→        ctx.inputTokens = event.message.usage.input_tokens ?? 0;
173→        ctx.cacheCreationTokens = event.message.usage.cache_creation_input_tokens ?? 0;
174→        ctx.cacheReadTokens = event.message.usage.cache_read_input_tokens ?? 0;
175→        ctx.model = event.message.model ?? ctx.model;
176→      }
177→
178→      if (event.type === "message_delta") {
179→        if (event.usage?.output_tokens) {
180→          ctx.outputTokens = event.usage.output_tokens;
181→        }
182→        if (event.delta?.stop_reason) {
183→          ctx.stopReason = event.delta.stop_reason;
184→        }
185→      }
186→    } catch {
187→      // partial JSON or non-JSON data line — skip
188→    }
189→  }
190→
191→  return remainder;
192→}
193→
194→// ---------------------------------------------------------------------------
195→// Non-Streaming Usage Extraction
196→// ---------------------------------------------------------------------------
197→
198→type NonStreamingResponse = {
199→  model?: string;
200→  usage?: {
201→    input_tokens?: number;
202→    output_tokens?: number;
203→    cache_creation_input_tokens?: number;
204→    cache_read_input_tokens?: number;
205→  };
206→  stop_reason?: string;
207→};
208→
209→function extractNonStreamingUsage(
210→  responseBody: string,
211→  requestModel: string | undefined,
212→  latencyMs: number,
213→  identity: { workspaceId?: string; taskId?: string },
214→  sessionId?: string,
215→  policyDecision?: PolicyDecisionLog,
216→  conversationId?: string,
217→  injectionResult?: InjectionResult,
218→): TraceData | undefined {
219→  try {
220→    const parsed = JSON.parse(responseBody) as NonStreamingResponse;
221→    if (!parsed.usage) return undefined;
222→
223→    const traceData: TraceData = {
224→      model: parsed.model ?? requestModel ?? "unknown",
225→      inputTokens: parsed.usage.input_tokens ?? 0,
226→      outputTokens: parsed.usage.output_tokens ?? 0,
227→      cacheCreationTokens: parsed.usage.cache_creation_input_tokens ?? 0,
228→      cacheReadTokens: parsed.usage.cache_read_input_tokens ?? 0,
229→      stopReason: parsed.stop_reason,
230→      latencyMs,
231→      workspaceId: identity.workspaceId,
232→      sessionId,
233→      taskId: identity.taskId,
234→      policyDecision,
235→      conversationId,
236→    };
237→
238→    // Add intelligence metadata if injection occurred
239→    if (injectionResult) {
240→      (traceData as any).intelligenceMetadata = buildIntelligenceMetadata(injectionResult);
241→    }
242→
243→    // Capture response content (opaque, per ADR-051)
244→    const responseContent = extractResponseContent(responseBody);
245→    if (responseContent) {
246→      (traceData as any).responseContent = responseContent;
247→    }
248→
249→    return traceData;
250→  } catch {
251→    return undefined;
252→  }
253→}
254→
255→// ---------------------------------------------------------------------------
256→// Context Candidate Pool Loader (adapter boundary)
257→// ---------------------------------------------------------------------------
258→
259→const DECISION_WEIGHT = 1.0;
260→const LEARNING_WEIGHT = 0.8;
261→const OBSERVATION_WEIGHT = 0.7;
262→
263→async function loadCandidatePool(
264→  surreal: ServerDependencies["surreal"],
265→  workspaceId: string,
266→): Promise<CachedCandidatePool> {
267→  const workspaceRecord = new RecordId("workspace", workspaceId);
268→
269→  type DecisionRow = { id: RecordId; summary: string; embedding?: number[] };
270→  type LearningRow = { id: RecordId; text: string; embedding?: number[] };
271→  type ObservationRow = { id: RecordId; text: string; embedding?: number[] };
272→
273→  // Sequential queries to avoid SurrealDB SDK concurrency issues with
274→  // multiple parallel queries on a single WebSocket connection
275→  const decisionResults = await surreal.query<[DecisionRow[]]>(
276→    `SELECT id, summary, embedding FROM decision WHERE workspace = $ws AND status = 'confirmed' LIMIT 50;`,
277→    { ws: workspaceRecord },
278→  );
279→  const learningResults = await surreal.query<[LearningRow[]]>(
280→    `SELECT id, text, embedding FROM learning WHERE workspace = $ws AND status = 'active' LIMIT 30;`,
281→    { ws: workspaceRecord },
282→  );
283→  const observationResults = await surreal.query<[ObservationRow[]]>(
284→    `SELECT id, text, embedding FROM observation WHERE workspace = $ws AND status = 'open' AND severity IN ['conflict', 'warning'] LIMIT 20;`,
285→    { ws: workspaceRecord },
286→  );
287→
288→  function toCandidates<T extends { id: RecordId; embedding?: number[] }>(
289→    rows: T[],
290→    type: CandidateItem["type"],
291→    weight: number,
292→    textFn: (row: T) => string,
293→  ): CandidateItem[] {
294→    return rows.map((row) => ({
295→      id: (row.id as RecordId).id as string,
296→      type,
297→      text: textFn(row),
298→      weight,
299→      embedding: row.embedding,
300→    }));
301→  }
302→
303→  const decisions = toCandidates(decisionResults[0] ?? [], "decision", DECISION_WEIGHT, (d) => d.summary);
304→  const learnings = toCandidates(learningResults[0] ?? [], "learning", LEARNING_WEIGHT, (l) => l.text);
305→  const observations = toCandidates(observationResults[0] ?? [], "observation", OBSERVATION_WEIGHT, (o) => o.text);
306→
307→  return {
308→    decisions,
309→    learnings,
310→    observations,
311→    populatedAt: Date.now(),
312→  };
313→}
314→
315→// ---------------------------------------------------------------------------
316→// Embedding Helper (adapter boundary)
317→// ---------------------------------------------------------------------------
318→
319→async function embedUserMessage(
320→  embeddingModel: ServerDependencies["embeddingModel"],
321→  embeddingDimension: number,
322→  text: string,
323→): Promise<number[] | undefined> {
324→  try {
325→    const { embed } = await import("ai");
326→    const normalized = text.trim();
327→    if (normalized.length === 0) return undefined;
328→
329→    const result = await embed({
330→      model: embeddingModel,
331→      value: normalized,
332→    });
333→
334→    if (result.embedding.length !== embeddingDimension) return undefined;
335→    return result.embedding;
336→  } catch {
337→    return undefined;
338→  }
339→}
340→
341→// ---------------------------------------------------------------------------
342→// Context Injection Pipeline (orchestrator)
343→// ---------------------------------------------------------------------------
344→
345→type ContextInjectionResult = {
346→  readonly body: string;
347→  readonly injectionResult?: InjectionResult;
348→};
349→
350→async function runContextInjection(
351→  deps: ServerDependencies,
352→  workspaceId: string,
353→  parsedBody: ParsedBody,
354→  originalBody: string,
355→  contextCache: ContextCache,
356→  intelligenceConfig: IntelligenceConfig,
357→): Promise<ContextInjectionResult> {
358→  if (!intelligenceConfig.contextInjectionEnabled) {
359→    return { body: originalBody };
360→  }
361→
362→  // 1. Get or populate candidate pool (with cache)
363→  let pool: CachedCandidatePool;
364→  if (contextCache.has(workspaceId)) {
365→    pool = contextCache.get(workspaceId)!;
366→  } else {
367→    pool = await loadCandidatePool(deps.surreal, workspaceId);
368→    contextCache.set(workspaceId, pool);
369→  }
370→
371→  // 2. Check if pool is empty
372→  const allCandidates: ContextCandidate[] = [
373→    ...pool.decisions,
374→    ...pool.learnings,
375→    ...pool.observations,
376→  ];
377→  if (allCandidates.length === 0) {
378→    logInfo("proxy.context_injection.empty_pool", "No candidates in pool", {
379→      workspace_id: workspaceId,
380→      decisions: pool.decisions.length,
381→      learnings: pool.learnings.length,
382→      observations: pool.observations.length,
383→    });
384→    return { body: originalBody };
385→  }
386→
387→  // 3. Extract last user message for embedding
388→  const lastUserMessage = [...(parsedBody.messages ?? [])].reverse().find((m) => m.role === "user");
389→  if (!lastUserMessage) {
390→    return { body: originalBody };
391→  }
392→
393→  // 4. Embed last user message
394→  const queryEmbedding = await embedUserMessage(
395→    deps.embeddingModel,
396→    deps.config.embeddingDimension,
397→    lastUserMessage.content,
398→  );
399→
400→  let selectedCandidates;
401→  if (queryEmbedding) {
402→    // 5. Rank candidates by weighted cosine similarity
403→    const ranked = rankCandidates(allCandidates, queryEmbedding);
404→    // 6. Select within token budget
405→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
406→  } else {
407→    // No embedding available -- fall back to all candidates within budget
408→    const ranked = allCandidates.map((c) => ({
409→      id: c.id,
410→      type: c.type,
411→      text: c.text,
412→      score: c.weight,
413→    }));
414→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
415→  }
416→
417→  if (selectedCandidates.length === 0) {
418→    return { body: originalBody };
419→  }
420→
421→  // 7. Build XML block
422→  const brainContextXml = buildBrainContextXml(selectedCandidates);
423→
424→  // 8. Inject into system prompt
425→  const injectionResult = injectBrainContext(parsedBody.system, brainContextXml);
426→
427→  // 9. Build modified request body
428→  const modifiedBody = {
429→    ...parsedBody,
430→    system: injectionResult.system,
431→  };
432→
433→  return {
434→    body: JSON.stringify(modifiedBody),
435→    injectionResult,
436→  };
437→}
438→
439→// ---------------------------------------------------------------------------
440→// Intelligence Metadata Builder (pure)
441→// ---------------------------------------------------------------------------
442→
443→function buildIntelligenceMetadata(injectionResult: InjectionResult) {
444→  return {
445→    brain_context_injected: injectionResult.injected,
446→    brain_context_decisions: injectionResult.decisionsCount,
447→    brain_context_learnings: injectionResult.learningsCount,
448→    brain_context_observations: injectionResult.observationsCount,
449→    brain_context_tokens_est: injectionResult.tokensEstimated,
450→  };
451→}
452→
453→// ---------------------------------------------------------------------------
454→// Non-Streaming Response Content Extraction (for trace output)
455→// ---------------------------------------------------------------------------
456→
457→type ResponseContent = {
458→  content_blocks: Array<{ type: string; text?: string; id?: string; name?: string; input?: unknown }>;
459→  stop_reason: string;
460→  usage: {
461→    input_tokens: number;
462→    output_tokens: number;
463→    cache_creation_tokens?: number;
464→    cache_read_tokens?: number;
465→  };
466→};
467→
468→function extractResponseContent(responseBody: string): ResponseContent | undefined {
469→  try {
470→    const parsed = JSON.parse(responseBody);
471→    if (!parsed.content || !parsed.usage) return undefined;
472→
473→    return {
474→      content_blocks: parsed.content,
475→      stop_reason: parsed.stop_reason ?? "end_turn",
476→      usage: {
477→        input_tokens: parsed.usage.input_tokens ?? 0,
478→        output_tokens: parsed.usage.output_tokens ?? 0,
479→        cache_creation_tokens: parsed.usage.cache_creation_input_tokens,
480→        cache_read_tokens: parsed.usage.cache_read_input_tokens,
481→      },
482→    };
483→  } catch {
484→    return undefined;
485→  }
486→}
487→
488→// ---------------------------------------------------------------------------
489→// Policy Denial Response Builder
490→// ---------------------------------------------------------------------------
491→
492→function buildPolicyDenialResponse(
493→  result: Exclude<ProxyPolicyResult, { decision: "allow" }>,
494→): Response {
495→  if (result.decision === "deny_rate_limit") {
496→    return new Response(JSON.stringify(result.body), {
497→      status: result.status,
498→      headers: {
499→        "Content-Type": "application/json",
500→        "Retry-After": String(result.retryAfterSeconds),
501→        "Access-Control-Allow-Origin": "*",
502→      },
503→    });
504→  }
505→  return jsonResponse(result.body, result.status);
506→}
507→
508→// ---------------------------------------------------------------------------
509→// Streaming Trace Builder
510→// ---------------------------------------------------------------------------
511→
512→function buildStreamingTraceData(
513→  streamCtx: StreamContext,
514→  latencyMs: number,
515→  identitySignals: import("./identity-resolver").IdentitySignals,
516→  effectiveSessionId: string | undefined,
517→  policyDecision: PolicyDecisionLog | undefined,
518→  conversationId: string | undefined,
519→  injectionResult: InjectionResult | undefined,
520→): TraceData {
521→  return {
522→    model: streamCtx.model!,
523→    inputTokens: streamCtx.inputTokens,
524→    outputTokens: streamCtx.outputTokens,
525→    cacheCreationTokens: streamCtx.cacheCreationTokens,
526→    cacheReadTokens: streamCtx.cacheReadTokens,
527→    stopReason: streamCtx.stopReason,
528→    latencyMs,
529→    workspaceId: identitySignals.workspaceId,
530→    sessionId: effectiveSessionId,
531→    taskId: identitySignals.taskId,
532→    policyDecision,
533→    conversationId,
534→    ...(injectionResult ? {
535→      intelligenceMetadata: buildIntelligenceMetadata(injectionResult),
536→    } : {}),
537→  };
538→}
539→
540→// ---------------------------------------------------------------------------
541→// Handler Factory
542→// ---------------------------------------------------------------------------
543→
544→export function createAnthropicProxyHandler(
545→  deps: ServerDependencies,
546→): (request: Request) => Promise<Response> {
547→  const workspaceCache: WorkspaceCache = new Map();
548→  const rateLimiterState: RateLimiterState = createRateLimiterState();
549→  const spendCache: SpendCache = new Map();
550→  const noPolicyWarnedWorkspaces = new Set<string>();
551→  const contextCache: ContextCache = createContextCache(300); // default TTL, overridden per-workspace
552→
553→  // Periodic pruning of stale rate limiter entries to prevent unbounded Map growth.
554→  // unref() ensures this interval does not keep the process alive on shutdown.
555→  const pruneInterval = setInterval(
556→    () => pruneStaleEntries(rateLimiterState, Date.now()),
557→    5 * 60 * 1000,
558→  );
559→  pruneInterval.unref();
560→
561→  const anthropicApiUrl = deps.config.anthropicApiUrl;
562→
563→  return async (request: Request): Promise<Response> => {
564→    const startedAt = performance.now();
565→    const url = new URL(request.url);
566→    const upstreamPath = url.pathname.replace(/^\/proxy\/llm\/anthropic/, "");
567→    const upstreamUrl = `${anthropicApiUrl}${upstreamPath}`;
568→    const isCountTokens = isCountTokensRequest(url.pathname);
569→
570→    // --- Step 1: Parse request body (malformed body forwarded as-is) ---
571→    const body = await request.text();
572→    const parsed = tryParseRequestBody(body);
573→    const isStreaming = parsed?.stream === true;
574→
575→    // --- Step 2: Identity resolution ---
576→    const identitySignals = resolveIdentity({
577→      metadataUserId: parsed?.metadata?.user_id,
578→      workspaceHeader: request.headers.get("X-Brain-Workspace") ?? undefined,
579→      taskHeader: request.headers.get("X-Brain-Task") ?? undefined,
580→      agentTypeHeader: request.headers.get("X-Brain-Agent-Type") ?? undefined,
581→      sessionHeader: request.headers.get("X-Brain-Session") ?? undefined,
582→    });
583→
584→    // --- Step 3: Session ID resolution ---
585→    const effectiveSessionId = resolveSessionId(identitySignals);
586→
587→    // --- Step 3.5: Conversation hash resolution (pure) ---
588→    const conversationHashInput: ConversationHashInput = {
589→      systemPrompt: typeof parsed?.system === "string" ? parsed.system : undefined,
590→      systemPromptBlocks: Array.isArray(parsed?.system) ? parsed.system : undefined,
591→      messages: parsed?.messages ?? [],
592→    };
593→    const conversationHash = resolveConversationHash(conversationHashInput);
594→
595→    // --- Conversation upsert (async, non-blocking) ---
596→    let conversationId: string | undefined;
597→    if (conversationHash && identitySignals.workspaceId) {
598→      try {
599→        const conversationRecord = await upsertConversation(
600→          {
601→            conversationId: conversationHash.conversationId,
602→            workspaceId: identitySignals.workspaceId,
603→            title: conversationHash.title,
604→          },
605→          { surreal: deps.surreal },
606→        );
607→        if (conversationRecord) {
608→          conversationId = conversationHash.conversationId;
609→        }
610→      } catch (error) {
611→        logWarn("proxy.anthropic.conversation_upsert_failed", "Conversation upsert failed — continuing without conversation link", {
612→          error: String(error),
613→        });
614→      }
615→    }
616→
617→    // --- Workspace validation (non-blocking) ---
618→    if (identitySignals.workspaceId) {
619→      const isValid = await validateWorkspace(
620→        deps.surreal,
621→        identitySignals.workspaceId,
622→        workspaceCache,
623→      );
624→      if (!isValid) {
625→        logWarn("proxy.anthropic.invalid_workspace", "Workspace not found in database", {
626→          workspaceId: identitySignals.workspaceId,
627→        });
628→      }
629→    }
630→
631→    // --- Step 4: Policy evaluation ---
632→    let policyResult: ProxyPolicyResult | undefined;
633→    if (parsed?.model && !isCountTokens) {
634→      const policyDeps: ProxyPolicyDependencies = {
635→        surreal: deps.surreal,
636→        inflight: deps.inflight,
637→        rateLimiterState,
638→        spendCache,
639→      };
640→
641→      policyResult = await evaluateProxyPolicy(
642→        {
643→          workspaceId: identitySignals.workspaceId ?? "",
644→          agentType: identitySignals.agentType,
645→          model: parsed.model,
646→        },
647→        policyDeps,
648→        noPolicyWarnedWorkspaces,
649→      );
650→
651→      if (policyResult.decision !== "allow") {
652→        return buildPolicyDenialResponse(policyResult);
653→      }
654→    }
655→
656→    // --- Step 5: Context injection (fail-open) ---
657→    let effectiveBody = body;
658→    let injectionResult: InjectionResult | undefined;
659→
660→    if (parsed && identitySignals.workspaceId && !isCountTokens) {
661→      try {
662→        const intelligenceConfig = await loadIntelligenceConfig(deps.surreal, identitySignals.workspaceId);
663→        const contextResult = await runContextInjection(
664→          deps,
665→          identitySignals.workspaceId,
666→          parsed,
667→          body,
668→          contextCache,
669→          intelligenceConfig,
670→        );
671→        effectiveBody = contextResult.body;
672→        injectionResult = contextResult.injectionResult;
673→        if (intelligenceConfig.contextInjectionEnabled) {
674→          logInfo("proxy.context_injection.result", "Context injection completed", {
675→            workspace_id: identitySignals.workspaceId,
676→            injected: injectionResult?.injected ?? false,
677→            decisions: injectionResult?.decisionsCount ?? 0,
678→            learnings: injectionResult?.learningsCount ?? 0,
679→          });
680→        }
681→      } catch (error) {
682→        // Fail-open: log warning and continue with original body
683→        logWarn("proxy.context_injection.failed", "Context injection failed, forwarding original request", {
684→          workspace_id: identitySignals.workspaceId,
685→          error: String(error),
686→        });
687→      }
688→    }
689→
690→    // --- API key validation ---
691→    const hasApiKey = request.headers.has("x-api-key");
692→    const hasAuthHeader = request.headers.has("authorization");
693→    if (!hasApiKey && !hasAuthHeader) {
694→      return jsonResponse(
695→        { error: "unauthorized", message: "Missing x-api-key or authorization header" },
696→        401,
697→      );
698→    }
699→
700→    // --- Build identity context for logging ---
701→    const identityContext = {
702→      user_hash: identitySignals.userHash,
703→      account_id: identitySignals.accountId,
704→      session_id: effectiveSessionId,
705→      workspace_id: identitySignals.workspaceId,
706→      task_id: identitySignals.taskId,
707→      agent_type: identitySignals.agentType,
708→      is_count_tokens: isCountTokens || undefined,
709→    };
710→
711→    logInfo("proxy.anthropic.request", "Forwarding to Anthropic", {
712→      method: request.method,
713→      url: upstreamUrl,
714→      ...identityContext,
715→    });
716→
717→    // --- Build policy decision for audit trail ---
718→    const policyDecision: PolicyDecisionLog | undefined = policyResult
719→      ? {
720→          decision: "pass",
721→          policy_refs: policyResult.decision === "allow" ? policyResult.policyIds : [],
722→          timestamp: new Date().toISOString(),
723→        }
724→      : undefined;
725→
726→    // --- Step 6: Request forwarding ---
727→    const upstreamHeaders = buildUpstreamHeaders(request);
728→
729→    let upstream: Response;
730→    try {
731→      upstream = await fetch(upstreamUrl, {
732→        method: request.method,
733→        headers: upstreamHeaders,
734→        body: request.method !== "GET" ? effectiveBody : undefined,
735→      });
736→    } catch (error) {
737→      logError("proxy.anthropic.upstream_error", "Failed to reach Anthropic API", error);
738→      return jsonResponse({ error: "upstream_unreachable", source: "proxy" }, 502);
739→    }
740→
741→    // --- Non-streaming response ---
742→    if (!isStreaming) {
743→      const responseBody = await upstream.text();
744→      const latencyMs = elapsedMs(startedAt);
745→
746→      logInfo("proxy.anthropic.response", "Anthropic response", {
747→        status: upstream.status,
748→        latency_ms: latencyMs,
749→        ...identityContext,
750→      });
751→
752→      // Async trace capture for non-streaming (skip count_tokens)
753→      if (!isCountTokens && upstream.status >= 200 && upstream.status < 300) {
754→        const traceData = extractNonStreamingUsage(responseBody, parsed?.model, latencyMs, identitySignals, effectiveSessionId, policyDecision, conversationId, injectionResult);
755→        if (traceData) {
756→          deps.inflight.track(
757→            captureTrace(traceData, { surreal: deps.surreal }).catch(() => undefined),
758→          );
759→        }
760→      }
761→
762→      return new Response(responseBody, {
763→        status: upstream.status,
764→        headers: {
765→          "Content-Type": upstream.headers.get("content-type") ?? "application/json",
766→          "Access-Control-Allow-Origin": "*",
767→        },
768→      });
769→    }
770→
771→    // --- Streaming: pipe SSE events through ---
772→    const { readable, writable } = new TransformStream<Uint8Array>();
773→    const writer = writable.getWriter();
774→    const reader = upstream.body!.getReader();
775→    const decoder = new TextDecoder();
776→
777→    const streamContext: StreamContext = {
778→      model: parsed?.model,
779→      inputTokens: 0,
780→      outputTokens: 0,
781→      cacheCreationTokens: 0,
782→      cacheReadTokens: 0,
783→      stopReason: undefined,
784→    };
785→
786→    (async () => {
787→      try {
788→        let buffer = "";
789→        while (true) {
790→          const { done, value } = await reader.read();
791→          if (done) break;
792→
793→          await writer.write(value);
794→
795→          buffer += decoder.decode(value, { stream: true });
796→          buffer = extractSSEUsage(buffer, streamContext);
797→        }
798→      } catch (error) {
799→        logError("proxy.anthropic.stream_error", "SSE relay error", error);
800→      } finally {
801→        await writer.close();
802→
803→        const latencyMs = elapsedMs(startedAt);
804→
805→        logInfo("proxy.anthropic.response", "Anthropic stream complete", {
806→          model: streamContext.model,
807→          input_tokens: streamContext.inputTokens,
808→          output_tokens: streamContext.outputTokens,
809→          cache_creation_tokens: streamContext.cacheCreationTokens,
810→          cache_read_tokens: streamContext.cacheReadTokens,
811→          stop_reason: streamContext.stopReason,
812→          latency_ms: latencyMs,
813→          ...identityContext,
814→        });
815→
816→        // Async trace capture for streaming (skip count_tokens)
817→        if (!isCountTokens && streamContext.model) {
818→          const traceData = buildStreamingTraceData(
819→            streamContext, latencyMs, identitySignals,
820→            effectiveSessionId, policyDecision, conversationId, injectionResult,
821→          );
822→          deps.inflight.track(
823→            captureTrace(traceData, { surreal: deps.surreal }).catch(() => undefined),
824→          );
825→        }
826→      }
827→    })();
828→
829→    return new Response(readable, {
830→      status: upstream.status,
831→      headers: {
832→        "Content-Type": "text/event-stream",
833→        "Cache-Control": "no-cache",
834→        "Connection": "keep-alive",
835→        "X-Accel-Buffering": "no",
836→        "Access-Control-Allow-Origin": "*",
837→      },
838→    });
839→  };
840→}
