      workspace: workspaceRecord,
      ...(embedding ? { embedding } : {}),
      created_at: now,
      updated_at: now,
    };
  }

  if (kind === "feature") {
    return {
      name: text,
      status: "active",
      workspace: workspaceRecord,
      ...(embedding ? { embedding } : {}),
      created_at: now,
      updated_at: now,
    };
  }

  if (kind === "task") {
    return {
      title: text,
      status: "open",
      extraction_confidence: confidence,
      extracted_at: now,
      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
      ...(embedding ? { embedding } : {}),
      ...(category ? { category } : {}),
      ...(priority ? { priority } : {}),
      workspace: workspaceRecord,
      created_at: now,
      updated_at: now,
    };
  }

  if (kind === "decision") {
    return {
      summary: text,
      status: "extracted",
      extraction_confidence: confidence,
      extracted_at: now,
      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
      ...(embedding ? { embedding } : {}),
      ...(category ? { category } : {}),
      ...(priority ? { priority } : {}),
      workspace: workspaceRecord,
      created_at: now,
      updated_at: now,
    };
  }

  // question (fallthrough)
  return {
    text,
    status: "open",
    extraction_confidence: confidence,
    extracted_at: now,
    ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
    ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
    ...(embedding ? { embedding } : {}),
    ...(category ? { category } : {}),
    ...(priority ? { priority } : {}),
    workspace: workspaceRecord,
    created_at: now,
    updated_at: now,
  };
}

export async function loadWorkspaceKindCandidates(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  kind: ExtractableEntityKind,
): Promise<CandidateEntityRow[]> {
  if (kind === "project") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        "SELECT id, name AS text, embedding FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  if (kind === "person") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        "SELECT id, name AS text, embedding FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  if (kind === "feature") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        [
          "SELECT id, name AS text, embedding",
          "FROM feature",
          "WHERE id IN (",
          "  SELECT VALUE out",
          "  FROM has_feature",
          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
          ");",
        ].join(" "),
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  if (kind === "task") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        "SELECT id, title AS text, embedding FROM task WHERE workspace = $workspace;",
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  if (kind === "decision") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        "SELECT id, summary AS text, embedding FROM decision WHERE workspace = $workspace;",
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  const [rows] = await surreal
    .query<[CandidateEntityRow[]]>(
      "SELECT id, text AS text, embedding FROM question WHERE workspace = $workspace;",
      { workspace: workspaceRecord },
    )
    .collect<[CandidateEntityRow[]]>();
  return rows;
}

export async function appendWorkspaceTools(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  toolsToAdd: string[],
  now: Date,
): Promise<void> {
  const [rows] = await surreal
    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
      workspace: workspaceRecord,
    })
    .collect<[Array<{ tools?: string[] }>]>();

  const existingTools = rows[0]?.tools ?? [];
  const merged = [...new Set([...existingTools, ...toolsToAdd])];
  await surreal.update(workspaceRecord).merge({
    tools: merged,
    updated_at: now,
  });
}

export function normalizeRelationshipKind(value: string): string {
  return value
    .trim()
    .replace(/[^a-zA-Z0-9]+/g, "_")
    .replace(/_+/g, "_")
    .replace(/^_/, "")
    .replace(/_$/, "")
    .toUpperCase();
}

function cosineSimilarity(a: number[], b: number[]): number {
  if (a.length !== b.length) {
    return -1;
  }

  let dot = 0;
  let normA = 0;
  let normB = 0;

  for (let i = 0; i < a.length; i += 1) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }

  if (normA === 0 || normB === 0) {
    return -1;
  }

  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

